import type {SequenceRecord, SequenceStep} from "./sequence-store";

export type SequencePlayerState = "idle" | "starting" | "transitioning" | "dwelling" | "holding";

export interface SequencePlayerSnapshot {
  state: SequencePlayerState;
  sequenceName: string | null;
  stepIndex: number;
  stepCount: number;
  stepName: string | null;
  round: number;
  totalRounds: number | null;
  remainingMs: number;
  currentStep: SequenceStep | null;
}

interface SequencePlayerDependencies {
  prepare(): Promise<void>;
  applyStep(step: SequenceStep, assertActive: () => void): Promise<void>;
  finished(reason: string, error?: unknown): void;
  changed(): void;
}

class SequenceCancelledError extends Error {}

export class SequencePlayer {
  private state: SequencePlayerState = "idle";
  private sequence: SequenceRecord | null = null;
  private stepIndex = -1;
  private round = 0;
  private remainingMs = 0;
  private deadline = 0;
  private generation = 0;
  private holdRequested = false;
  private rescheduleRequested = false;
  private timer: number | null = null;
  private interruptWait: (() => void) | null = null;
  private resumeWait: (() => void) | null = null;

  constructor(private readonly dependencies: SequencePlayerDependencies) {}

  get active(): boolean {
    return this.state !== "idle";
  }

  get holding(): boolean {
    return this.state === "holding";
  }

  get snapshot(): SequencePlayerSnapshot {
    const remainingMs = this.state === "dwelling"
      ? Math.max(0, this.deadline - performance.now())
      : this.remainingMs;
    return {
      state: this.state,
      sequenceName: this.sequence?.name ?? null,
      stepIndex: this.stepIndex,
      stepCount: this.sequence?.steps.length ?? 0,
      stepName: this.sequence && this.stepIndex >= 0 ? this.sequence.steps[this.stepIndex]?.name ?? null : null,
      round: this.round,
      totalRounds: this.sequence?.repeat.mode === "count" ? this.sequence.repeat.rounds : null,
      remainingMs,
      currentStep: this.sequence && this.stepIndex >= 0 ? this.sequence.steps[this.stepIndex] ?? null : null,
    };
  }

  start(sequence: SequenceRecord): void {
    if (this.active) throw new Error("已有序列正在运行");
    this.sequence = structuredClone(sequence);
    this.stepIndex = -1;
    this.round = 1;
    this.remainingMs = 0;
    this.holdRequested = false;
    const generation = ++this.generation;
    this.setState("starting");
    void this.run(generation);
  }

  updateSequence(sequence: SequenceRecord): void {
    if (!this.active) throw new Error("当前没有正在运行的序列");
    const previousStep = this.sequence && this.stepIndex >= 0 ? this.sequence.steps[this.stepIndex] ?? null : null;
    const previousRemaining = this.snapshot.remainingMs;
    this.sequence = structuredClone(sequence);
    if (!previousStep) {
      this.dependencies.changed();
      return;
    }

    const nextIndex = this.sequence.steps.findIndex((step) => step.id === previousStep.id);
    if (nextIndex < 0) {
      this.remainingMs = 0;
      this.holdRequested = false;
      if (this.state === "dwelling") {
        this.rescheduleRequested = true;
        this.interruptWait?.();
      } else if (this.state === "holding") {
        this.resumeWait?.();
        this.resumeWait = null;
      }
    } else {
      this.stepIndex = nextIndex;
      const nextStep = this.sequence.steps[nextIndex];
      if (nextStep && nextStep.durationMs !== previousStep.durationMs
        && (this.state === "dwelling" || this.state === "holding")) {
        const elapsedMs = Math.max(0, previousStep.durationMs - previousRemaining);
        this.remainingMs = Math.max(0, nextStep.durationMs - elapsedMs);
        if (this.state === "dwelling") {
          this.rescheduleRequested = true;
          this.interruptWait?.();
        }
      }
    }
    this.dependencies.changed();
  }

  hold(): void {
    if (!this.active || this.state === "holding") return;
    this.holdRequested = true;
    if (this.state === "dwelling") {
      this.remainingMs = Math.max(0, this.deadline - performance.now());
      this.clearTimer();
      this.interruptWait?.();
    }
    this.dependencies.changed();
  }

  resume(): void {
    if (this.state !== "holding") return;
    this.holdRequested = false;
    this.rescheduleRequested = false;
    this.resumeWait?.();
    this.resumeWait = null;
  }

  cancel(): boolean {
    const wasActive = this.active;
    this.generation += 1;
    this.clearTimer();
    this.interruptWait?.();
    this.resumeWait?.();
    this.interruptWait = null;
    this.resumeWait = null;
    this.holdRequested = false;
    this.sequence = null;
    this.stepIndex = -1;
    this.round = 0;
    this.remainingMs = 0;
    this.setState("idle");
    return wasActive;
  }

  private async run(generation: number): Promise<void> {
    try {
      await this.dependencies.prepare();
      this.assertActive(generation);
      let cursor = 0;
      while (true) {
        this.assertActive(generation);
        const sequence = this.sequence;
        if (!sequence) throw new SequenceCancelledError();
        if (cursor >= sequence.steps.length) {
          if (sequence.repeat.mode === "count" && this.round >= sequence.repeat.rounds) break;
          this.round += 1;
          cursor = 0;
          this.dependencies.changed();
          continue;
        }

        const step = sequence.steps[cursor];
        if (!step) throw new Error("序列步骤不存在");
        this.stepIndex = cursor;
        this.setState("transitioning");
        await this.dependencies.applyStep(step, () => this.assertActive(generation));
        this.assertActive(generation);

        const updatedSequence = this.sequence;
        if (!updatedSequence) throw new SequenceCancelledError();
        const updatedIndex = updatedSequence.steps.findIndex((candidate) => candidate.id === step.id);
        if (updatedIndex < 0) {
          cursor = Math.min(cursor, updatedSequence.steps.length);
          continue;
        }
        this.stepIndex = updatedIndex;
        this.remainingMs = updatedSequence.steps[updatedIndex]?.durationMs ?? 0;
        await this.dwell(generation);

        const latestSequence = this.sequence;
        if (!latestSequence) throw new SequenceCancelledError();
        const latestIndex = latestSequence.steps.findIndex((candidate) => candidate.id === step.id);
        cursor = latestIndex < 0 ? Math.min(cursor, latestSequence.steps.length) : latestIndex + 1;
      }
      this.assertActive(generation);
      this.dependencies.finished("序列播放完成");
    } catch (error) {
      if (error instanceof SequenceCancelledError || generation !== this.generation) return;
      this.dependencies.finished("序列播放失败", error);
    }
  }

  private async dwell(generation: number): Promise<void> {
    while (this.remainingMs > 0) {
      this.assertActive(generation);
      if (this.holdRequested) {
        this.setState("holding");
        await new Promise<void>((resolve) => { this.resumeWait = resolve; });
        this.resumeWait = null;
        this.assertActive(generation);
        continue;
      }

      this.setState("dwelling");
      this.deadline = performance.now() + this.remainingMs;
      await new Promise<void>((resolve) => {
        this.interruptWait = resolve;
        this.timer = window.setTimeout(resolve, this.remainingMs);
      });
      this.interruptWait = null;
      this.clearTimer();
      if (this.holdRequested || this.rescheduleRequested) {
        this.rescheduleRequested = false;
        continue;
      }
      this.remainingMs = 0;
    }
  }

  private assertActive(generation: number): void {
    if (generation !== this.generation || !this.sequence) throw new SequenceCancelledError();
  }

  private clearTimer(): void {
    if (this.timer !== null) window.clearTimeout(this.timer);
    this.timer = null;
  }

  private setState(state: SequencePlayerState): void {
    this.state = state;
    this.dependencies.changed();
  }
}
