import {App} from "@capacitor/app";
import {Capacitor} from "@capacitor/core";
import {CapacitorUpdater} from "@capgo/capacitor-updater";

export interface NativeUpdateController {
  checkForUpdate(): Promise<NativeUpdateCheckResult>;
}

export type NativeUpdateCheckResult =
  | {status: "up-to-date"}
  | {status: "not-applicable"}
  | {status: "ready"; version: string; downloaded: boolean};

interface NativeUpdateManifest {
  schema: 1;
  enabled: boolean;
  channel?: string;
  version?: string;
  bundleUrl?: string;
  sha256?: string;
  minNativeBuild?: number;
  maxNativeBuild?: number;
  protocolRevision?: number;
  publishedAt?: string;
  mandatory?: boolean;
  allowDowngrade?: boolean;
  signature?: string;
}

interface NativeUpdaterOptions {
  onCurrentVersion(version: string): void;
  onDownloaded(version: string): void;
  onError(error: unknown): void;
  onRollback(version: string): void;
}

const CHECK_INTERVAL_MS = 15 * 60 * 1_000;
const CHECK_TIMEOUT_MS = 15_000;
const PROTOCOL_REVISION = 1;

export async function registerNativeUpdater(
  options: NativeUpdaterOptions,
): Promise<NativeUpdateController | null> {
  if (!Capacitor.isNativePlatform()) return null;

  const ready = await CapacitorUpdater.notifyAppReady();
  if (ready.bundle.status === "error") options.onRollback(ready.bundle.version);
  const activeBundle = await CapacitorUpdater.current();
  options.onCurrentVersion(activeBundle.bundle.version);

  let activeCheck: Promise<NativeUpdateCheckResult> | null = null;
  let lastCheckedAt = 0;

  const checkForUpdate = (): Promise<NativeUpdateCheckResult> => {
    if (activeCheck) return activeCheck;
    const check = (async (): Promise<NativeUpdateCheckResult> => {
      if (!navigator.onLine) throw new Error("当前设备处于离线状态");
      lastCheckedAt = Date.now();
      const manifestUrl = new URL(__OTA_MANIFEST_URL__);
      manifestUrl.searchParams.set("t", String(Date.now()));
      const controller = new AbortController();
      const timeout = window.setTimeout(() => controller.abort(), CHECK_TIMEOUT_MS);
      let response: Response;
      try {
        response = await fetch(manifestUrl, {
          cache: "no-store",
          headers: {Accept: "application/json"},
          signal: controller.signal,
        });
      } catch (error) {
        if (controller.signal.aborted) throw new Error("更新清单请求超时，请检查网络连接");
        throw error;
      } finally {
        window.clearTimeout(timeout);
      }
      if (!response.ok) throw new Error(`更新清单请求失败：HTTP ${response.status}`);

      const manifest = parseManifest(await response.json());
      if (!manifest.enabled) return {status: "up-to-date"};
      const version = manifest.version;
      const bundleUrl = manifest.bundleUrl;
      const sha256 = manifest.sha256;
      if (!version || !bundleUrl || !sha256) throw new Error("启用的更新清单缺少 version、bundleUrl 或 sha256");
      if (!manifest.signature) throw new Error("启用的更新清单缺少 RSA 签名");
      if (!__OTA_PUBLIC_KEY__) throw new Error("原生安装包没有配置 OTA 验签公钥");
      if (!await verifyManifestSignature(manifest, __OTA_PUBLIC_KEY__)) {
        throw new Error("更新清单 RSA 签名无效");
      }
      if (manifest.protocolRevision !== undefined && manifest.protocolRevision !== PROTOCOL_REVISION) {
        throw new Error(`OTA 协议版本不兼容：${manifest.protocolRevision}`);
      }

      const appInfo = await App.getInfo();
      const nativeBuild = Number.parseInt(appInfo.build, 10);
      if (!Number.isFinite(nativeBuild)) throw new Error(`无法识别原生构建号：${appInfo.build}`);
      if (manifest.minNativeBuild !== undefined && nativeBuild < manifest.minNativeBuild) {
        return {status: "not-applicable"};
      }
      if (manifest.maxNativeBuild !== undefined && nativeBuild > manifest.maxNativeBuild) {
        return {status: "not-applicable"};
      }

      const current = await CapacitorUpdater.current();
      const currentVersion = current.bundle.version === "builtin" ? appInfo.version : current.bundle.version;
      if (currentVersion === version) return {status: "up-to-date"};
      if (!manifest.allowDowngrade && compareVersions(version, currentVersion) <= 0) {
        return {status: "up-to-date"};
      }

      const pending = await CapacitorUpdater.getNextBundle();
      if (pending?.version === version) return {status: "ready", version, downloaded: false};

      let existing = (await CapacitorUpdater.list()).bundles.find((bundle) => bundle.version === version);
      if (existing && existing.checksum.toLowerCase() !== sha256.toLowerCase()) {
        await CapacitorUpdater.delete({id: existing.id});
        existing = undefined;
      }
      const bundle = existing ?? await CapacitorUpdater.download({
        version,
        url: new URL(bundleUrl, manifestUrl).href,
        checksum: sha256,
      });
      await CapacitorUpdater.next({id: bundle.id});
      options.onDownloaded(version);
      return {status: "ready", version, downloaded: true};
    })().catch((error: unknown) => {
      options.onError(error);
      throw error;
    }).finally(() => {
      activeCheck = null;
    });
    activeCheck = check;
    return check;
  };

  const checkAutomatically = (): void => {
    void checkForUpdate().catch(() => {
      // 自动检查失败已通过 onError 报告，不影响应用继续运行。
    });
  };

  await App.addListener("appStateChange", ({isActive}) => {
    if (isActive && Date.now() - lastCheckedAt >= CHECK_INTERVAL_MS) checkAutomatically();
  });
  window.addEventListener("online", checkAutomatically);
  checkAutomatically();
  return {checkForUpdate};
}

function parseManifest(value: unknown): NativeUpdateManifest {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new Error("更新清单不是 JSON 对象");
  }
  const manifest = value as Partial<NativeUpdateManifest>;
  if (manifest.schema !== 1 || typeof manifest.enabled !== "boolean") {
    throw new Error("更新清单 schema 或 enabled 无效");
  }
  return manifest as NativeUpdateManifest;
}

function compareVersions(left: string, right: string): number {
  const parse = (version: string): number[] => version
    .replace(/^v/i, "")
    .split(/[.+-]/)
    .slice(0, 3)
    .map((part) => Number.parseInt(part, 10) || 0);
  const a = parse(left);
  const b = parse(right);
  for (let index = 0; index < 3; index += 1) {
    const difference = (a[index] ?? 0) - (b[index] ?? 0);
    if (difference !== 0) return Math.sign(difference);
  }
  return 0;
}

function signedManifestPayload(manifest: NativeUpdateManifest): string {
  return JSON.stringify({
    schema: manifest.schema,
    enabled: manifest.enabled,
    channel: manifest.channel,
    version: manifest.version,
    bundleUrl: manifest.bundleUrl,
    sha256: manifest.sha256,
    minNativeBuild: manifest.minNativeBuild,
    maxNativeBuild: manifest.maxNativeBuild,
    protocolRevision: manifest.protocolRevision,
    publishedAt: manifest.publishedAt,
    mandatory: manifest.mandatory,
    allowDowngrade: manifest.allowDowngrade,
  });
}

async function verifyManifestSignature(
  manifest: NativeUpdateManifest,
  publicKeyPem: string,
): Promise<boolean> {
  const keyBytes = pemBytes(publicKeyPem, "PUBLIC KEY");
  const key = await crypto.subtle.importKey(
    "spki",
    Uint8Array.from(keyBytes).buffer,
    {name: "RSASSA-PKCS1-v1_5", hash: "SHA-256"},
    false,
    ["verify"],
  );
  const signature = Uint8Array.from(atob(manifest.signature ?? ""), (character) => character.charCodeAt(0));
  return crypto.subtle.verify(
    "RSASSA-PKCS1-v1_5",
    key,
    Uint8Array.from(signature).buffer,
    new TextEncoder().encode(signedManifestPayload(manifest)).buffer,
  );
}

function pemBytes(pem: string, label: string): Uint8Array {
  const base64 = pem
    .replace(`-----BEGIN ${label}-----`, "")
    .replace(`-----END ${label}-----`, "")
    .replace(/\s/g, "");
  if (!base64) throw new Error("OTA 验签公钥格式无效");
  return Uint8Array.from(atob(base64), (character) => character.charCodeAt(0));
}
