import {Capacitor} from "@capacitor/core";

export interface PwaUpdateController {
  applyUpdate(): boolean;
  checkForUpdate(): Promise<void>;
}

interface RegisterPwaOptions {
  canReload(): boolean;
  onUpdateDeferred(): void;
}

const UPDATE_CHECK_INTERVAL_MS = 60 * 60 * 1_000;

export async function registerPwa(
  options: RegisterPwaOptions,
): Promise<PwaUpdateController | null> {
  if (Capacitor.isNativePlatform()) return null;
  if (!("serviceWorker" in navigator) || !window.isSecureContext) return null;
  if (window.location.hostname === "localhost" && window.location.port === "8080") return null;

  const registration = await navigator.serviceWorker.register("./service-worker.js", {
    updateViaCache: "none",
  });
  let activationRequested = false;

  const applyUpdate = (): boolean => {
    if (!registration.waiting || !options.canReload()) return false;
    activationRequested = true;
    registration.waiting.postMessage({type: "SKIP_WAITING"});
    return true;
  };

  const updateIsReady = (): void => {
    if (!navigator.serviceWorker.controller) return;
    if (!applyUpdate()) options.onUpdateDeferred();
  };

  const watchInstallingWorker = (worker: ServiceWorker): void => {
    worker.addEventListener("statechange", () => {
      if (worker.state === "installed") updateIsReady();
    });
  };

  navigator.serviceWorker.addEventListener("controllerchange", () => {
    if (activationRequested) window.location.reload();
  });

  registration.addEventListener("updatefound", () => {
    if (registration.installing) watchInstallingWorker(registration.installing);
  });

  const checkForUpdate = async (): Promise<void> => {
    if (!navigator.onLine) return;
    try {
      await registration.update();
    } catch {
      // 离线或网络切换中的更新失败不影响当前缓存版本。
    }
  };

  if (registration.waiting) updateIsReady();

  window.addEventListener("online", () => void checkForUpdate());
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState !== "visible") return;
    void checkForUpdate();
    applyUpdate();
  });
  window.setInterval(() => void checkForUpdate(), UPDATE_CHECK_INTERVAL_MS);

  void checkForUpdate();
  return {applyUpdate, checkForUpdate};
}
