import type {MemorySettings} from "./memory-store";

export type BandMode = "extract" | "edge";
export type BandTransitionType = "ramp" | "hold" | "jump";

export interface BandTransition {
  type: BandTransitionType;
  durationMs: number;
}

export interface BandPoint {
  id: string;
  sourceMemoryId?: string;
  name: string;
  mode: BandMode;
  settings: MemorySettings;
  toNext: BandTransition;
}

export type BandRepeat =
  | {mode: "forever"}
  | {mode: "count"; rounds: number};

export interface BandRecord {
  id: string;
  name: string;
  points: BandPoint[];
  repeat: BandRepeat;
  createdAt: string;
  updatedAt: string;
}

export type BandDraft = Omit<BandRecord, "id" | "createdAt" | "updatedAt"> & {
  id?: string;
  createdAt?: string;
};

export interface BandExport {
  schema: "milk-band-export/v1";
  exportedAt: string;
  band: BandDraft;
}

const DATABASE_NAME = "milk-control-bands.v1";
const STORE_NAME = "bands";
const MAXIMUM_DURATION_MS = 3_600_000;

function newId(prefix: string): string {
  return typeof crypto.randomUUID === "function"
    ? crypto.randomUUID()
    : `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function requestResult<T>(request: IDBRequest<T>): Promise<T> {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("IndexedDB 操作失败"));
  });
}

function transactionDone(transaction: IDBTransaction): Promise<void> {
  return new Promise((resolve, reject) => {
    transaction.oncomplete = () => resolve();
    transaction.onabort = () => reject(transaction.error ?? new Error("IndexedDB 事务已取消"));
    transaction.onerror = () => reject(transaction.error ?? new Error("IndexedDB 事务失败"));
  });
}

function openDatabase(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DATABASE_NAME, 1);
    request.onupgradeneeded = () => {
      if (!request.result.objectStoreNames.contains(STORE_NAME)) {
        request.result.createObjectStore(STORE_NAME, {keyPath: "id"});
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("无法打开波段数据库"));
  });
}

async function withStore<T>(
  mode: IDBTransactionMode,
  action: (store: IDBObjectStore) => IDBRequest<T>,
): Promise<T> {
  const database = await openDatabase();
  try {
    const transaction = database.transaction(STORE_NAME, mode);
    const done = transactionDone(transaction);
    const result = await requestResult(action(transaction.objectStore(STORE_NAME)));
    await done;
    return result;
  } finally {
    database.close();
  }
}

function integerBetween(value: unknown, minimum: number, maximum: number): value is number {
  return Number.isInteger(value) && (value as number) >= minimum && (value as number) <= maximum;
}

function normalizeSettings(value: unknown): MemorySettings {
  if (!value || typeof value !== "object") throw new Error("波段参数点缺少 YPSCM 设置");
  const settings = value as Partial<MemorySettings>;
  if (!integerBetween(settings.suctionPressure, 0, 0xff)
    || !integerBetween(settings.blowPower, 0, 0xff)
    || !integerBetween(settings.suctionMs, 0, 999)
    || !Number.isInteger(settings.secondPhaseMs)
    || (settings.secondPhaseMs as number) < -0x7fff
    || (settings.secondPhaseMs as number) > 0x80fff
    || (settings.suctionMs as number) - (settings.secondPhaseMs as number) < -0x8000
    || (settings.suctionMs as number) - (settings.secondPhaseMs as number) > 0x7fff) {
    throw new Error("波段参数点超出协议允许范围");
  }
  return {...settings} as MemorySettings;
}

function normalizeTransition(value: unknown): BandTransition {
  if (!value || typeof value !== "object") throw new Error("波段参数点缺少到下一点的过渡设置");
  const candidate = value as Partial<BandTransition>;
  if (candidate.type !== "ramp" && candidate.type !== "hold" && candidate.type !== "jump") {
    throw new Error("波段包含未知过渡方式");
  }
  const durationMs = candidate.type === "jump" ? 0 : candidate.durationMs;
  if (!integerBetween(durationMs, 100, MAXIMUM_DURATION_MS) && candidate.type !== "jump") {
    throw new Error("渐变或保持时间必须为 0.1–3600 秒");
  }
  return {type: candidate.type, durationMs: durationMs as number};
}

function normalizePoint(value: unknown): BandPoint {
  if (!value || typeof value !== "object") throw new Error("波段参数点格式不正确");
  const point = value as Partial<BandPoint>;
  if (typeof point.name !== "string" || point.name.trim().length === 0 || point.name.trim().length > 80) {
    throw new Error("参数点名称必须为 1–80 个字符");
  }
  if (point.mode !== "extract" && point.mode !== "edge") throw new Error("参数点包含未知模式 M");
  return {
    id: typeof point.id === "string" && point.id ? point.id : newId("band-point"),
    ...(typeof point.sourceMemoryId === "string" && point.sourceMemoryId ? {sourceMemoryId: point.sourceMemoryId} : {}),
    name: point.name.trim(),
    mode: point.mode,
    settings: normalizeSettings(point.settings),
    toNext: normalizeTransition(point.toNext),
  };
}

export function normalizeBand(value: BandDraft): BandDraft {
  if (typeof value.name !== "string" || value.name.trim().length === 0 || value.name.trim().length > 80) {
    throw new Error("波段名称必须为 1–80 个字符");
  }
  if (!Array.isArray(value.points) || value.points.length < 2 || value.points.length > 100) {
    throw new Error("波段必须包含 2–100 个参数点");
  }
  let repeat: BandRepeat;
  if (value.repeat?.mode === "forever") repeat = {mode: "forever"};
  else if (value.repeat?.mode === "count" && integerBetween(value.repeat.rounds, 1, 999)) {
    repeat = {mode: "count", rounds: value.repeat.rounds};
  } else throw new Error("波段循环次数必须为 1–999，或选择一直循环");
  const points = value.points.map(normalizePoint);
  if (points.every((point) => point.toNext.type === "jump")) {
    throw new Error("闭环波段至少需要一段渐变或定时保持，不能全部直接跳变");
  }
  return {
    ...(value.id ? {id: value.id} : {}),
    ...(value.createdAt ? {createdAt: value.createdAt} : {}),
    name: value.name.trim(),
    points,
    repeat,
  };
}

export async function listBands(): Promise<BandRecord[]> {
  const stored = await withStore<BandRecord[]>("readonly", (store) => store.getAll());
  return stored.map((record) => ({...record, ...normalizeBand(record)}))
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt));
}

export async function saveBand(value: BandDraft): Promise<BandRecord> {
  const normalized = normalizeBand(value);
  const now = new Date().toISOString();
  const record: BandRecord = {
    id: normalized.id ?? newId("band"),
    name: normalized.name,
    points: normalized.points,
    repeat: normalized.repeat,
    createdAt: normalized.createdAt ?? now,
    updatedAt: now,
  };
  await withStore("readwrite", (store) => store.put(record));
  return record;
}

export async function deleteBand(id: string): Promise<void> {
  await withStore("readwrite", (store) => store.delete(id));
}

export function createBandExport(value: BandDraft): BandExport {
  const normalized = normalizeBand(value);
  return {
    schema: "milk-band-export/v1",
    exportedAt: new Date().toISOString(),
    band: {name: normalized.name, points: normalized.points, repeat: normalized.repeat},
  };
}

export function importBandFile(contents: string): BandDraft {
  let parsed: unknown;
  try {
    parsed = JSON.parse(contents);
  } catch {
    throw new Error("载入文件不是有效的 JSON");
  }
  if (!parsed || typeof parsed !== "object") throw new Error("载入文件格式不正确");
  const envelope = parsed as {schema?: string; band?: BandDraft};
  if (envelope.schema !== "milk-band-export/v1" || !envelope.band) {
    throw new Error("仅支持 milk-band-export/v1 波段文件");
  }
  const normalized = normalizeBand(envelope.band);
  return {name: normalized.name, points: normalized.points, repeat: normalized.repeat};
}
