import {BleClient, type BleDevice} from "@capacitor-community/bluetooth-le";
import {Capacitor} from "@capacitor/core";

export interface BleTransportOptions {
  serviceUuid: string;
  writeUuid: string;
  notifyUuid: string;
  onDisconnect(): void;
  onNotification(value: DataView): void;
}

export interface BleConnectOptions {
  deviceName?: string;
}

/**
 * Cross-platform BLE central transport. BleClient uses native BLE in Capacitor
 * and falls back to Web Bluetooth in supported browsers.
 */
export class BleTransport {
  private device: BleDevice | null = null;
  private initialized = false;
  private isConnected = false;
  private disconnecting = false;
  private connectGeneration = 0;

  constructor(private readonly options: BleTransportOptions) {}

  static isSupported(): boolean {
    return Capacitor.isNativePlatform()
      || (typeof navigator !== "undefined" && "bluetooth" in navigator);
  }

  static isNative(): boolean {
    return Capacitor.isNativePlatform();
  }

  get connected(): boolean {
    return this.isConnected;
  }

  get deviceName(): string | null {
    return this.device?.name ?? null;
  }

  async connect(options: BleConnectOptions): Promise<void> {
    if (this.device || this.isConnected) throw new Error("蓝牙传输层已经连接");
    const generation = ++this.connectGeneration;
    await this.initialize();
    if (generation !== this.connectGeneration) throw new Error("蓝牙连接已取消");

    const device = await BleClient.requestDevice(options.deviceName
      ? {name: options.deviceName, optionalServices: [this.options.serviceUuid]}
      : {services: [this.options.serviceUuid]});
    if (generation !== this.connectGeneration) throw new Error("蓝牙连接已取消");
    this.device = device;

    try {
      await BleClient.connect(device.deviceId, this.handleDisconnect, {timeout: 15_000});
      if (generation !== this.connectGeneration) throw new Error("蓝牙连接已取消");
      await BleClient.startNotifications(
        device.deviceId,
        this.options.serviceUuid,
        this.options.notifyUuid,
        this.options.onNotification,
        {timeout: 10_000},
      );
      if (generation !== this.connectGeneration) throw new Error("蓝牙连接已取消");
      this.isConnected = true;
    } catch (cause) {
      await this.releaseDevice();
      throw cause;
    }
  }

  async disconnect(): Promise<void> {
    this.connectGeneration += 1;
    const device = this.device;
    if (!device) return;

    this.disconnecting = true;
    this.isConnected = false;
    try {
      await BleClient.stopNotifications(
        device.deviceId,
        this.options.serviceUuid,
        this.options.notifyUuid,
      ).catch(() => undefined);
      await BleClient.disconnect(device.deviceId).catch(() => undefined);
    } finally {
      this.device = null;
      this.disconnecting = false;
    }
  }

  async write(data: Uint8Array): Promise<void> {
    const device = this.device;
    if (!device || !this.isConnected) throw new Error("蓝牙设备未连接");

    const value = new DataView(data.buffer, data.byteOffset, data.byteLength);
    await BleClient.write(
      device.deviceId,
      this.options.serviceUuid,
      this.options.writeUuid,
      value,
      {timeout: 5_000},
    );
  }

  private async initialize(): Promise<void> {
    if (this.initialized) return;
    await BleClient.initialize({androidNeverForLocation: true});
    BleClient.enableQueue();
    this.initialized = true;
  }

  private readonly handleDisconnect = (): void => {
    this.isConnected = false;
    this.device = null;
    if (!this.disconnecting) this.options.onDisconnect();
  };

  private async releaseDevice(): Promise<void> {
    const device = this.device;
    this.isConnected = false;
    this.device = null;
    if (device) await BleClient.disconnect(device.deviceId).catch(() => undefined);
  }
}
