import type {PluginListenerHandle} from "@capacitor/core";
import {Capacitor, registerPlugin} from "@capacitor/core";

interface BackgroundModePlugin {
  start(): Promise<void>;
  stop(): Promise<void>;
  isRunning(): Promise<{running: boolean}>;
  addListener(eventName: "taskRemoved", listener: () => void): Promise<PluginListenerHandle>;
}

const NativeBackgroundMode = registerPlugin<BackgroundModePlugin>("BackgroundMode");

export function isNativeBackgroundModeAvailable(): boolean {
  return Capacitor.getPlatform() === "android";
}

export async function startNativeBackgroundMode(): Promise<void> {
  if (isNativeBackgroundModeAvailable()) await NativeBackgroundMode.start();
}

export async function stopNativeBackgroundMode(): Promise<void> {
  if (isNativeBackgroundModeAvailable()) await NativeBackgroundMode.stop();
}

export async function nativeBackgroundModeIsRunning(): Promise<boolean> {
  if (!isNativeBackgroundModeAvailable()) return false;
  return (await NativeBackgroundMode.isRunning()).running;
}

export async function onNativeTaskRemoved(listener: () => void): Promise<PluginListenerHandle | null> {
  if (!isNativeBackgroundModeAvailable()) return null;
  return NativeBackgroundMode.addListener("taskRemoved", listener);
}
