export type MemoryMode = "stopped" | "extract" | "edge";

export interface MemorySettings {
  suctionPressure: number;
  blowPower: number;
  suctionMs: number;
  secondPhaseMs: number;
}

export interface MemoryRecord {
  id: string;
  name: string;
  mode: MemoryMode;
  settings: MemorySettings;
  createdAt: string;
  updatedAt: string;
  system?: boolean;
}

export interface MemoryExport {
  schema: "milk-memory-export/v3";
  exportedAt: string;
  records: MemoryRecord[];
}

const DATABASE_NAME = "milk-control-memories.v1";
const STORE_NAME = "records";
const DEFAULT_ID = "default-all-stopped";
const MODES: readonly MemoryMode[] = ["stopped", "extract", "edge"];

export const DEFAULT_MEMORY: MemoryRecord = {
  id: DEFAULT_ID,
  name: "全部停止",
  mode: "stopped",
  settings: {suctionPressure: 0, blowPower: 0, suctionMs: 999, secondPhaseMs: 999},
  createdAt: "1970-01-01T00:00:00.000Z",
  updatedAt: "1970-01-01T00:00:00.000Z",
  system: true,
};

function requestResult<T>(request: IDBRequest<T>): Promise<T> {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("IndexedDB 操作失败"));
  });
}

function transactionDone(transaction: IDBTransaction): Promise<void> {
  return new Promise((resolve, reject) => {
    transaction.oncomplete = () => resolve();
    transaction.onabort = () => reject(transaction.error ?? new Error("IndexedDB 事务已取消"));
    transaction.onerror = () => reject(transaction.error ?? new Error("IndexedDB 事务失败"));
  });
}

function openDatabase(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DATABASE_NAME, 2);
    request.onupgradeneeded = (event) => {
      const database = request.result;
      if (event.oldVersion === 0) {
        const store = database.createObjectStore(STORE_NAME, {keyPath: "id"});
        store.put(DEFAULT_MEMORY);
        return;
      }
      const store = request.transaction?.objectStore(STORE_NAME);
      if (!store || event.oldVersion >= 2) return;
      const cursorRequest = store.openCursor();
      cursorRequest.onsuccess = () => {
        const cursor = cursorRequest.result;
        if (!cursor) return;
        const record = cursor.value as MemoryRecord;
        cursor.update({...record, settings: migrateLegacyTiming(record.settings) as MemorySettings});
        cursor.continue();
      };
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("无法打开 IndexedDB"));
  });
}

async function withStore<T>(
  mode: IDBTransactionMode,
  action: (store: IDBObjectStore) => IDBRequest<T>,
): Promise<T> {
  const database = await openDatabase();
  try {
    const transaction = database.transaction(STORE_NAME, mode);
    const done = transactionDone(transaction);
    const result = await requestResult(action(transaction.objectStore(STORE_NAME)));
    await done;
    return result;
  } finally {
    database.close();
  }
}

function isIntegerBetween(value: unknown, minimum: number, maximum: number): value is number {
  return Number.isInteger(value) && (value as number) >= minimum && (value as number) <= maximum;
}

function normalizeMode(value: unknown, settings?: Partial<MemorySettings>): MemoryMode {
  if (value === "standalone") return "extract";
  if (value === "pulse") return (settings?.blowPower ?? 0) > 0 ? "extract" : "edge";
  if (typeof value === "string" && MODES.includes(value as MemoryMode)) return value as MemoryMode;
  throw new Error("记录包含未知模式");
}

function migrateLegacyTiming(settings: Partial<MemorySettings> | undefined): Partial<MemorySettings> | undefined {
  if (!settings || typeof settings.suctionMs !== "number" || typeof settings.secondPhaseMs !== "number") return settings;
  return {
    ...settings,
    secondPhaseMs: 2 * settings.suctionMs - settings.secondPhaseMs,
  };
}

function normalizedRecord(value: unknown, imported = false, legacyTiming = false): MemoryRecord {
  if (!value || typeof value !== "object") throw new Error("记录必须是对象");
  const candidate = value as Partial<MemoryRecord>;
  const candidateSettings = candidate.settings as Partial<MemorySettings> | undefined;
  const settings = legacyTiming ? migrateLegacyTiming(candidateSettings) : candidateSettings;
  if (typeof candidate.name !== "string" || candidate.name.trim().length === 0 || candidate.name.trim().length > 80) {
    throw new Error("记录名称必须为 1–80 个字符");
  }
  const mode = normalizeMode((value as {mode?: unknown}).mode, settings);
  if (!settings
    || !isIntegerBetween(settings.suctionPressure, 0, 0xff)
    || !isIntegerBetween(settings.blowPower, 0, 0xff)
    || !isIntegerBetween(settings.suctionMs, 0, 999)
    || typeof settings.secondPhaseMs !== "number"
    || !Number.isInteger(settings.secondPhaseMs)
    || settings.suctionMs - settings.secondPhaseMs < -0x8000
    || settings.suctionMs - settings.secondPhaseMs > 0x7fff) {
    throw new Error("记录参数超出允许范围");
  }
  const now = new Date().toISOString();
  const id = imported || typeof candidate.id !== "string" || candidate.id.length === 0
    ? typeof crypto.randomUUID === "function"
      ? crypto.randomUUID()
      : `memory-${Date.now()}-${Math.random().toString(16).slice(2)}`
    : candidate.id;
  return {
    id,
    name: candidate.name.trim(),
    mode,
    settings: {...settings} as MemorySettings,
    createdAt: imported ? now : typeof candidate.createdAt === "string" ? candidate.createdAt : now,
    updatedAt: now,
    ...(candidate.system === true && id === DEFAULT_ID ? {system: true} : {}),
  };
}

async function ensureDefaultMemory(): Promise<void> {
  const existing = await withStore("readonly", (store) => store.get(DEFAULT_ID));
  if (!existing || (existing as MemoryRecord).settings.suctionMs !== DEFAULT_MEMORY.settings.suctionMs) {
    await withStore("readwrite", (store) => store.put(DEFAULT_MEMORY));
  }
}

export async function listMemories(): Promise<MemoryRecord[]> {
  await ensureDefaultMemory();
  const stored = await withStore<Array<MemoryRecord & {mode: unknown}>>("readonly", (store) => store.getAll());
  const records = stored.map((record) => {
    return {...record, settings: {...record.settings}, mode: normalizeMode(record.mode, record.settings)};
  });
  return records.sort((left, right) => {
    if (left.system) return -1;
    if (right.system) return 1;
    return right.updatedAt.localeCompare(left.updatedAt);
  });
}

export async function saveMemory(record: Omit<MemoryRecord, "id" | "createdAt" | "updatedAt">): Promise<MemoryRecord> {
  const saved = normalizedRecord(record);
  await withStore("readwrite", (store) => store.put(saved));
  return saved;
}

export async function deleteMemory(id: string): Promise<void> {
  if (id === DEFAULT_ID) throw new Error("默认“全部停止”记录不能删除");
  await withStore("readwrite", (store) => store.delete(id));
}

export function createMemoryExport(records: MemoryRecord[]): MemoryExport {
  return {schema: "milk-memory-export/v3", exportedAt: new Date().toISOString(), records};
}

export async function importMemoryFile(contents: string): Promise<number> {
  let parsed: unknown;
  try {
    parsed = JSON.parse(contents);
  } catch {
    throw new Error("导入文件不是有效的 JSON");
  }
  if (!parsed || typeof parsed !== "object") throw new Error("导入文件格式不正确");
  const envelope = parsed as {schema?: string; records?: unknown[]};
  if ((envelope.schema !== "milk-memory-export/v1"
      && envelope.schema !== "milk-memory-export/v2"
      && envelope.schema !== "milk-memory-export/v3")
    || !Array.isArray(envelope.records)) {
    throw new Error("仅支持 milk-memory-export/v1、v2 或 v3 格式");
  }
  const imported = envelope.records
    .filter((record) => {
      if (!record || typeof record !== "object") return true;
      const candidate = record as {id?: unknown; system?: unknown};
      return candidate.id !== DEFAULT_ID && candidate.system !== true;
    })
    .map((record) => normalizedRecord(record, true, envelope.schema !== "milk-memory-export/v3"));
  if (imported.length === 0) return 0;

  const database = await openDatabase();
  try {
    const transaction = database.transaction(STORE_NAME, "readwrite");
    const done = transactionDone(transaction);
    const store = transaction.objectStore(STORE_NAME);
    imported.forEach((record) => store.put(record));
    await done;
  } finally {
    database.close();
  }
  return imported.length;
}
