import {BleTransport} from "./BleTransport";

export type ConnectionState = "disconnected" | "connecting" | "connected" | "disconnecting";

export interface ControllerLogEntry {
  timestamp: string;
  direction: "TX" | "RX" | "INFO" | "ERROR";
  label: string;
  bytes?: number[];
  detail?: string;
}

export interface ControllerEventMap {
  connection: { state: ConnectionState; deviceName: string | null };
  log: ControllerLogEntry;
  notification: { bytes: number[] };
  fault: { message: string; cause?: unknown };
}

type ControllerEventName = keyof ControllerEventMap;
type ControllerListener<K extends ControllerEventName> = (detail: ControllerEventMap[K]) => void;

export interface ConnectOptions {
  deviceName?: string;
  requestTimeoutMs?: number;
}

const SERVICE_UUID = "0000fff0-0000-1000-8000-00805f9b34fb";
const WRITE_UUID = "0000fff2-0000-1000-8000-00805f9b34fb";
const NOTIFY_UUID = "0000fff1-0000-1000-8000-00805f9b34fb";

export abstract class BaseController {
  static readonly SERVICE_UUID = SERVICE_UUID;
  static readonly WRITE_UUID = WRITE_UUID;
  static readonly NOTIFY_UUID = NOTIFY_UUID;

  private state: ConnectionState = "disconnected";
  private readonly transport: BleTransport;
  private heartbeatTimer: number | null = null;
  private writeQueue: Promise<void> = Promise.resolve();
  private lastWriteAt = 0;
  private readonly listeners = new Map<ControllerEventName, Set<(detail: never) => void>>();
  private readonly minimumWriteGapMs = 45;
  private readonly heartbeatMs = 20_000;
  private readonly demoDeviceName = "Milk UI Simulator";

  constructor(private readonly demoMode = false) {
    this.transport = new BleTransport({
      serviceUuid: SERVICE_UUID,
      writeUuid: WRITE_UUID,
      notifyUuid: NOTIFY_UUID,
      onDisconnect: () => this.cleanupConnection("设备连接已断开"),
      onNotification: (value) => this.handleNotification(value),
    });
  }

  private handleNotification(value: DataView): void {
    const bytes = Array.from(new Uint8Array(value.buffer, value.byteOffset, value.byteLength));
    this.emitLog("RX", "notification", bytes);
    this.emit("notification", {bytes});

    try {
      this.handleNotify(value);
    } catch (cause) {
      this.reportFault("无法解析设备通知", cause);
    }
  }

  get connectionState(): ConnectionState {
    return this.state;
  }

  get connected(): boolean {
    return this.state === "connected"
      && (this.demoMode || this.transport.connected);
  }

  get deviceName(): string | null {
    return this.demoMode ? this.demoDeviceName : this.transport.deviceName;
  }

  get isDemoMode(): boolean {
    return this.demoMode;
  }

  static isBluetoothSupported(): boolean {
    return BleTransport.isSupported();
  }

  static isNativeBluetooth(): boolean {
    return BleTransport.isNative();
  }

  on<K extends ControllerEventName>(event: K, listener: ControllerListener<K>): () => void {
    const listeners = this.listeners.get(event) ?? new Set<(detail: never) => void>();
    listeners.add(listener as (detail: never) => void);
    this.listeners.set(event, listeners);
    return () => listeners.delete(listener as (detail: never) => void);
  }

  async connect(options: ConnectOptions = {}): Promise<void> {
    if (this.state !== "disconnected") {
      throw new Error(`当前连接状态不允许连接：${this.state}`);
    }

    this.setConnectionState("connecting");
    if (this.demoMode) {
      try {
        await this.delay(180);
        this.setConnectionState("connected");
        await this.afterConnect();
        this.emitLog("INFO", "demo-connected", undefined, `${this.demoDeviceName}（未访问蓝牙）`);
        return;
      } catch (cause) {
        this.cleanupConnection("模拟连接初始化失败");
        throw cause;
      }
    }

    if (!BaseController.isBluetoothSupported()) {
      this.cleanupConnection("浏览器不支持 Web Bluetooth");
      throw new Error("当前浏览器不支持 Web Bluetooth。请在 Android 或桌面版 Chrome 的安全上下文中打开。");
    }

    try {
      await this.withTimeout(
        this.transport.connect({
          ...(options.deviceName ? {deviceName: options.deviceName} : {}),
        }),
        options.requestTimeoutMs ?? 60_000,
        "选择蓝牙设备超时",
      );

      this.setConnectionState("connected");
      await this.afterConnect();
      this.emitLog("INFO", "connected", undefined, this.transport.deviceName ?? "未命名设备");
      this.scheduleHeartbeat();
    } catch (cause) {
      await this.transport.disconnect();
      this.cleanupConnection("连接失败");
      throw cause;
    }
  }

  async disconnect(): Promise<void> {
    if (this.state === "disconnected") return;
    this.stopHeartbeat();

    try {
      await this.beforeDisconnect();
      await this.flushWrites();
    } catch (cause) {
      this.reportFault("断开前的安全停机未完全执行", cause);
    } finally {
      this.setConnectionState("disconnecting");
      await this.transport.disconnect();
      this.cleanupConnection("已主动断开");
    }
  }

  async flushWrites(): Promise<void> {
    await this.writeQueue;
  }

  protected abstract handleNotify(data: DataView): void;

  protected async afterConnect(): Promise<void> {
    // Subclasses may initialize the device into a known safe state before
    // connect() is reported as successfully completed.
  }

  protected async beforeDisconnect(): Promise<void> {
    // Subclasses may send a best-effort zero-output sequence.
  }

  protected onConnectionClosed(): void {
    // Subclasses may clear local safety timers and state.
  }

  protected onHeartbeatFailure(): void {
    // Subclasses may invalidate local running state when the device watchdog
    // is expected to stop output after a missed heartbeat.
  }

  protected async sendFrame(id: number, high: number, low: number, label: string): Promise<void> {
    for (const [name, value] of [["id", id], ["high", high], ["low", low]] as const) {
      if (!Number.isInteger(value) || value < 0 || value > 0xff) {
        throw new RangeError(`${name} 必须是 0-255 的整数`);
      }
    }
    await this.sendRaw(new Uint8Array([0xff, id, high, low, 0xfe]), label);
  }

  protected async sendRaw(data: Uint8Array, label: string): Promise<void> {
    const payload = new Uint8Array(data);
    const operation = async (): Promise<void> => {
      if (!this.connected) throw new Error(this.demoMode ? "模拟设备未连接" : "蓝牙设备未连接");

      const waitMs = Math.max(0, this.minimumWriteGapMs - (Date.now() - this.lastWriteAt));
      if (waitMs > 0) await this.delay(waitMs);

      if (this.demoMode) {
        await this.delay(12);
      } else {
        await this.transport.write(payload);
      }
      this.lastWriteAt = Date.now();
      this.emitLog("TX", this.demoMode ? `SIM ${label}` : label, Array.from(payload));
    };

    const queued = this.writeQueue.catch(() => undefined).then(operation);
    this.writeQueue = queued.catch((cause) => {
      this.reportFault(`写入失败：${label}`, cause);
    });
    return queued;
  }

  protected emitLog(
    direction: ControllerLogEntry["direction"],
    label: string,
    bytes?: number[],
    detail?: string,
  ): void {
    const entry: ControllerLogEntry = {
      timestamp: new Date().toISOString(),
      direction,
      label,
      ...(bytes ? {bytes} : {}),
      ...(detail ? {detail} : {}),
    };
    this.emit("log", entry);
  }

  protected reportFault(message: string, cause?: unknown): void {
    const detail = cause instanceof Error ? cause.message : cause ? String(cause) : undefined;
    this.emitLog("ERROR", "fault", undefined, detail ? `${message}：${detail}` : message);
    this.emit("fault", {...(cause === undefined ? {} : {cause}), message});
  }

  protected delay(milliseconds: number): Promise<void> {
    return new Promise((resolve) => window.setTimeout(resolve, milliseconds));
  }

  private emit<K extends ControllerEventName>(event: K, detail: ControllerEventMap[K]): void {
    this.listeners.get(event)?.forEach((listener) => listener(detail as never));
  }

  private setConnectionState(state: ConnectionState): void {
    this.state = state;
    this.emit("connection", {state, deviceName: this.deviceName});
  }

  private scheduleHeartbeat(): void {
    this.stopHeartbeat();
    const tick = async (): Promise<void> => {
      if (!this.connected) return;
      try {
        await this.sendRaw(new Uint8Array([0x01]), "heartbeat");
      } catch {
        // sendRaw already reports the fault. Retry only while the GATT connection remains alive.
        this.onHeartbeatFailure();
      }
      if (this.connected) this.heartbeatTimer = window.setTimeout(tick, this.heartbeatMs);
    };
    this.heartbeatTimer = window.setTimeout(tick, this.heartbeatMs);
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer !== null) {
      window.clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  private cleanupConnection(reason: string): void {
    this.stopHeartbeat();
    this.writeQueue = Promise.resolve();
    this.onConnectionClosed();
    this.setConnectionState("disconnected");
    this.emitLog("INFO", "disconnected", undefined, reason);
  }

  private async withTimeout<T>(promise: Promise<T>, milliseconds: number, message: string): Promise<T> {
    let timer: number | undefined;
    const timeout = new Promise<never>((_, reject) => {
      timer = window.setTimeout(() => reject(new Error(message)), milliseconds);
    });
    try {
      return await Promise.race([promise, timeout]);
    } finally {
      if (timer !== undefined) window.clearTimeout(timer);
    }
  }
}
