import type {MemoryMode, MemorySettings} from "./memory-store";

export type SequenceMode = Exclude<MemoryMode, "stopped">;

export interface SequenceStep {
  id: string;
  sourceMemoryId?: string;
  name: string;
  mode: SequenceMode;
  settings: MemorySettings;
  durationMs: number;
}

export type SequenceRepeat =
  | {mode: "forever"}
  | {mode: "count"; rounds: number};

export interface SequenceRecord {
  id: string;
  name: string;
  steps: SequenceStep[];
  repeat: SequenceRepeat;
  createdAt: string;
  updatedAt: string;
}

export type SequenceDraft = Omit<SequenceRecord, "id" | "createdAt" | "updatedAt"> & {
  id?: string;
  createdAt?: string;
};

export interface SequenceExport {
  schema: "milk-sequence-export/v3";
  exportedAt: string;
  sequence: SequenceDraft;
}

const DATABASE_NAME = "milk-control-sequences.v1";
const STORE_NAME = "sequences";
const MODES: readonly SequenceMode[] = ["extract", "edge"];
const MINIMUM_DURATION_MS = 1_000;
const MAXIMUM_DURATION_MS = 3_600_000;

function newId(prefix: string): string {
  return typeof crypto.randomUUID === "function"
    ? crypto.randomUUID()
    : `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function requestResult<T>(request: IDBRequest<T>): Promise<T> {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("IndexedDB 操作失败"));
  });
}

function transactionDone(transaction: IDBTransaction): Promise<void> {
  return new Promise((resolve, reject) => {
    transaction.oncomplete = () => resolve();
    transaction.onabort = () => reject(transaction.error ?? new Error("IndexedDB 事务已取消"));
    transaction.onerror = () => reject(transaction.error ?? new Error("IndexedDB 事务失败"));
  });
}

function openDatabase(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DATABASE_NAME, 2);
    request.onupgradeneeded = (event) => {
      if (event.oldVersion === 0) {
        request.result.createObjectStore(STORE_NAME, {keyPath: "id"});
        return;
      }
      const store = request.transaction?.objectStore(STORE_NAME);
      if (!store || event.oldVersion >= 2) return;
      const cursorRequest = store.openCursor();
      cursorRequest.onsuccess = () => {
        const cursor = cursorRequest.result;
        if (!cursor) return;
        const sequence = cursor.value as SequenceRecord;
        cursor.update({
          ...sequence,
          steps: sequence.steps.map((step) => ({...step, settings: migrateLegacyTiming(step.settings)})),
        });
        cursor.continue();
      };
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error ?? new Error("无法打开序列数据库"));
  });
}

async function withStore<T>(
  mode: IDBTransactionMode,
  action: (store: IDBObjectStore) => IDBRequest<T>,
): Promise<T> {
  const database = await openDatabase();
  try {
    const transaction = database.transaction(STORE_NAME, mode);
    const done = transactionDone(transaction);
    const result = await requestResult(action(transaction.objectStore(STORE_NAME)));
    await done;
    return result;
  } finally {
    database.close();
  }
}

function integerBetween(value: unknown, minimum: number, maximum: number): value is number {
  return Number.isInteger(value) && (value as number) >= minimum && (value as number) <= maximum;
}

function migrateLegacyTiming(settings: MemorySettings): MemorySettings {
  return {...settings, secondPhaseMs: 2 * settings.suctionMs - settings.secondPhaseMs};
}

function normalizeSettings(value: unknown, legacyTiming = false): MemorySettings {
  if (!value || typeof value !== "object") throw new Error("序列步骤缺少设置参数");
  const candidate = value as Partial<MemorySettings>;
  const settings: Partial<MemorySettings> = legacyTiming
    ? migrateLegacyTiming(candidate as MemorySettings)
    : candidate;
  if (!integerBetween(settings.suctionPressure, 0, 0xff)
    || !integerBetween(settings.blowPower, 0, 0xff)
    || !integerBetween(settings.suctionMs, 0, 999)
    || typeof settings.secondPhaseMs !== "number"
    || !Number.isInteger(settings.secondPhaseMs)
    || settings.suctionMs - settings.secondPhaseMs < -0x8000
    || settings.suctionMs - settings.secondPhaseMs > 0x7fff) {
    throw new Error("序列步骤参数超出允许范围");
  }
  return {...settings} as MemorySettings;
}

function normalizeMode(value: unknown, settings: MemorySettings): SequenceMode {
  if (value === "standalone") return "extract";
  if (value === "pulse") return settings.blowPower > 0 ? "extract" : "edge";
  if (typeof value === "string" && MODES.includes(value as SequenceMode)) return value as SequenceMode;
  throw new Error("序列步骤包含未知循环模式");
}

function normalizeStep(value: unknown, legacyTiming = false): SequenceStep {
  if (!value || typeof value !== "object") throw new Error("序列步骤格式不正确");
  const step = value as Partial<SequenceStep>;
  if (typeof step.name !== "string" || step.name.trim().length === 0 || step.name.trim().length > 80) {
    throw new Error("步骤名称必须为 1–80 个字符");
  }
  const settings = normalizeSettings(step.settings, legacyTiming);
  const mode = normalizeMode((value as {mode?: unknown}).mode, settings);
  if (!integerBetween(step.durationMs, MINIMUM_DURATION_MS, MAXIMUM_DURATION_MS)) {
    throw new Error("每个步骤的持续时间必须为 1–3600 秒");
  }
  return {
    id: typeof step.id === "string" && step.id ? step.id : newId("step"),
    ...(typeof step.sourceMemoryId === "string" && step.sourceMemoryId ? {sourceMemoryId: step.sourceMemoryId} : {}),
    name: step.name.trim(),
    mode,
    settings,
    durationMs: step.durationMs,
  };
}

export function normalizeSequence(value: SequenceDraft, legacyTiming = false): SequenceDraft {
  if (typeof value.name !== "string" || value.name.trim().length === 0 || value.name.trim().length > 80) {
    throw new Error("序列名称必须为 1–80 个字符");
  }
  if (!Array.isArray(value.steps) || value.steps.length === 0 || value.steps.length > 100) {
    throw new Error("序列必须包含 1–100 个步骤");
  }
  let repeat: SequenceRepeat;
  if (value.repeat?.mode === "forever") repeat = {mode: "forever"};
  else if (value.repeat?.mode === "count" && integerBetween(value.repeat.rounds, 1, 999)) {
    repeat = {mode: "count", rounds: value.repeat.rounds};
  } else throw new Error("循环次数必须为 1–999，或选择一直循环");

  return {
    ...(value.id ? {id: value.id} : {}),
    ...(value.createdAt ? {createdAt: value.createdAt} : {}),
    name: value.name.trim(),
    steps: value.steps.map((step) => normalizeStep(step, legacyTiming)),
    repeat,
  };
}

export async function listSequences(): Promise<SequenceRecord[]> {
  const stored = await withStore<SequenceRecord[]>("readonly", (store) => store.getAll());
  const records = stored.map((record) => {
    const normalized = normalizeSequence(record);
    return {...record, ...normalized, id: record.id, createdAt: record.createdAt, updatedAt: record.updatedAt};
  });
  return records.sort((left, right) => right.updatedAt.localeCompare(left.updatedAt));
}

export async function saveSequence(value: SequenceDraft): Promise<SequenceRecord> {
  const normalized = normalizeSequence(value);
  const now = new Date().toISOString();
  const record: SequenceRecord = {
    id: normalized.id ?? newId("sequence"),
    name: normalized.name,
    steps: normalized.steps,
    repeat: normalized.repeat,
    createdAt: normalized.createdAt ?? now,
    updatedAt: now,
  };
  await withStore("readwrite", (store) => store.put(record));
  return record;
}

export async function deleteSequence(id: string): Promise<void> {
  await withStore("readwrite", (store) => store.delete(id));
}

export function createSequenceExport(value: SequenceDraft): SequenceExport {
  const normalized = normalizeSequence(value);
  return {
    schema: "milk-sequence-export/v3",
    exportedAt: new Date().toISOString(),
    sequence: {
      name: normalized.name,
      steps: normalized.steps,
      repeat: normalized.repeat,
    },
  };
}

export function importSequenceFile(contents: string): SequenceDraft {
  let parsed: unknown;
  try {
    parsed = JSON.parse(contents);
  } catch {
    throw new Error("载入文件不是有效的 JSON");
  }
  if (!parsed || typeof parsed !== "object") throw new Error("载入文件格式不正确");
  const envelope = parsed as {schema?: string; sequence?: SequenceDraft};
  if ((envelope.schema !== "milk-sequence-export/v1"
      && envelope.schema !== "milk-sequence-export/v2"
      && envelope.schema !== "milk-sequence-export/v3")
    || !envelope.sequence) {
    throw new Error("仅支持 milk-sequence-export/v1、v2 或 v3 格式");
  }
  const normalized = normalizeSequence(envelope.sequence, envelope.schema !== "milk-sequence-export/v3");
  return {
    name: normalized.name,
    steps: normalized.steps,
    repeat: normalized.repeat,
  };
}
