import {BaseController} from "./BaseController";
import {assertInteger, encodeInt16BE, encodeUint16BE} from "./protocol";

export const MILK_DEVICE_NAME = "君箫旨善-S";

export enum MilkOperation {
  SelectEdgeCycle = 0,
  SelectExtractCycle = 1,
  HoldSuction = 4,
  RunPulse = 5,
  SetPressureY = 9,
}

export type MilkPauseFlag = 0 | 1;
export const MILK_PAUSE_FLAG: MilkPauseFlag = 0;
export const MILK_RUN_FLAG: MilkPauseFlag = 1;

export interface MilkCycleConfig {
  suctionPressure: number;
  blowPower: number;
  suctionMs: number;
  secondPhaseMs: number;
}

export interface MilkStatus {
  raw: number[];
  type: number;
  suctionPressure: number;
  label: "榨取" | "边缘" | "持续只吸" | "脉冲" | "未知";
}

export type MilkPressureChannel = "suction" | "blow";
export type MilkCycleMode = "extract" | "edge";
export type MilkMotionMode = "pulse" | "hold-suction";

export interface MilkSuctionHoldOptions {
  useFixedPressure: boolean;
  fixedPressure: number;
}

export interface MilkPressureState {
  suctionPressure: number;
  blowPower: number;
  activeChannel: MilkPressureChannel | null;
  deflection: number;
  ratePerSecond: number;
  step: number;
}

const STATUS_LABELS: Readonly<Record<number, MilkStatus["label"]>> = {
  1: "榨取",
  2: "边缘",
  4: "持续只吸",
  5: "脉冲",
};

const PROTOCOL_PRESSURE_MAX = 0xff;
export const MILK_SUCTION_MAX_MS = 999;
const MILK_PHASE_DELTA_MIN = -0x8000;
const MILK_PHASE_DELTA_MAX = 0x7fff;
const PRESSURE_DEAD_ZONE = 0.12;

export class MilkController extends BaseController {
  private cycle: MilkCycleConfig = {
    suctionPressure: 0,
    blowPower: 0,
    suctionMs: MILK_SUCTION_MAX_MS,
    secondPhaseMs: MILK_SUCTION_MAX_MS,
  };
  private running = false;
  private paused = false;
  private cycleMode: MilkCycleMode = "edge";
  private motionMode: MilkMotionMode = "pulse";
  private suctionHoldActive = false;
  private suctionHoldUsesFixedPressure = false;
  private suctionHoldRestoreConfig: MilkCycleConfig | null = null;
  private statusListeners = new Set<(status: MilkStatus) => void>();
  private pressureListeners = new Set<(state: MilkPressureState) => void>();
  private pressureState: MilkPressureState = {
    suctionPressure: 0,
    blowPower: 0,
    activeChannel: null,
    deflection: 0,
    ratePerSecond: 0,
    step: 1,
  };
  private pressureGeneration = 0;
  private pressureLoop: Promise<void> = Promise.resolve();

  constructor(demoMode = false) {
    super(demoMode);
  }

  get isRunning(): boolean {
    return this.running;
  }

  get isPaused(): boolean {
    return this.paused;
  }

  get currentCycleMode(): MilkCycleMode {
    return this.cycleMode;
  }

  get currentMotionMode(): MilkMotionMode {
    return this.motionMode;
  }

  get isSuctionHoldActive(): boolean {
    return this.suctionHoldActive;
  }

  get isSuctionHoldUsingFixedPressure(): boolean {
    return this.suctionHoldActive && this.suctionHoldUsesFixedPressure;
  }

  get currentCycle(): Readonly<MilkCycleConfig> {
    return {...this.cycle};
  }

  get currentPressure(): Readonly<MilkPressureState> {
    return {...this.pressureState};
  }

  onStatus(listener: (status: MilkStatus) => void): () => void {
    this.statusListeners.add(listener);
    return () => this.statusListeners.delete(listener);
  }

  onPressureChange(listener: (state: MilkPressureState) => void): () => void {
    this.pressureListeners.add(listener);
    listener(this.currentPressure);
    return () => this.pressureListeners.delete(listener);
  }

  async configureCycle(config: MilkCycleConfig): Promise<void> {
    this.requireConnected();
    this.validateCycle(config);

    await this.emergencyStop("应用参数前停机");
    this.cycle = {...config, suctionPressure: 0, blowPower: 0};
    await this.setSuctionDuration(config.suctionMs);
    await this.setPhaseDelta(config.suctionMs - config.secondPhaseMs);
    this.emitLog("INFO", "cycle-configured", undefined, JSON.stringify(this.cycle));
  }

  async configureRunningCycle(config: MilkCycleConfig): Promise<void> {
    this.requireRunning();
    this.requireSuctionHoldReleased();
    this.validateCycle(config);
    if (config.suctionMs !== this.cycle.suctionMs) await this.setSuctionDuration(config.suctionMs);
    const phaseDelta = config.suctionMs - config.secondPhaseMs;
    const currentPhaseDelta = this.cycle.suctionMs - this.cycle.secondPhaseMs;
    if (phaseDelta !== currentPhaseDelta) await this.setPhaseDelta(phaseDelta);
    this.cycle.suctionMs = config.suctionMs;
    this.cycle.secondPhaseMs = config.secondPhaseMs;
    this.emitLog("INFO", "running-cycle-configured", undefined, JSON.stringify(this.cycle));
  }

  async applyRunningPreset(
    config: MilkCycleConfig,
    mode: MilkCycleMode,
    assertActive: () => void = () => undefined,
  ): Promise<void> {
    this.requireRunning();
    this.requireSuctionHoldReleased();
    this.validateCycle(config);
    this.stopPressureRamp();
    assertActive();

    // A sequence step is a complete device snapshot. Always rewrite every
    // setting so the result does not depend on cached state or a missed frame
    // from the previous step.
    await this.synchronizeCycleState(config, mode, MILK_RUN_FLAG, "sequence-full", {assertActive});
    assertActive();
    this.cycle = {...config};
    this.cycleMode = mode;
    this.setPressureValues(config.suctionPressure, config.blowPower);
    this.emitDemoStatus(mode === "extract" ? 1 : 2, config.suctionPressure);
  }

  async applyRunningWaveFrame(
    config: MilkCycleConfig,
    mode: MilkCycleMode,
    complete: boolean,
    assertActive: () => void = () => undefined,
  ): Promise<void> {
    this.requireRunning();
    this.requireSuctionHoldReleased();
    this.validateCycle(config);
    this.stopPressureRamp();
    assertActive();

    if (complete || mode !== this.cycleMode) {
      // A cycle-mode (M) transition is always a complete snapshot, even in
      // the middle of an otherwise incremental wave segment.
      await this.applyRunningPreset(config, mode, assertActive);
      return;
    }

    if (config.suctionMs !== this.cycle.suctionMs) {
      await this.setSuctionDuration(config.suctionMs);
      assertActive();
    }
    const phaseDelta = config.suctionMs - config.secondPhaseMs;
    const currentPhaseDelta = this.cycle.suctionMs - this.cycle.secondPhaseMs;
    if (phaseDelta !== currentPhaseDelta) {
      await this.setPhaseDelta(phaseDelta);
      assertActive();
    }
    this.cycle.suctionMs = config.suctionMs;
    this.cycle.secondPhaseMs = config.secondPhaseMs;

    if (config.suctionPressure !== this.pressureState.suctionPressure) {
      await this.writeChannelPressure("suction", config.suctionPressure, "band-frame");
      assertActive();
    }
    if (config.blowPower !== this.pressureState.blowPower) {
      await this.writeChannelPressure("blow", config.blowPower, "band-frame");
      assertActive();
    }
  }

  beginPressureRamp(channel: MilkPressureChannel, deflection: number): void {
    this.requireRunning();
    this.requirePressureAdjustmentAllowed(channel);
    this.assertDeflection(deflection);
    this.pressureGeneration += 1;
    const generation = this.pressureGeneration;
    this.pressureState.activeChannel = channel;
    this.pressureState.deflection = deflection;
    this.pressureState.ratePerSecond = 0;
    this.pressureState.step = 1;
    this.emitPressureState();
    this.pressureLoop = this.pressureLoop
      .catch(() => undefined)
      .then(() => this.runPressureRamp(generation))
      .catch(() => {
        if (generation === this.pressureGeneration) this.stopPressureRamp();
      });
  }

  updatePressureRamp(channel: MilkPressureChannel, deflection: number): void {
    this.assertDeflection(deflection);
    if (this.pressureState.activeChannel !== channel) {
      this.beginPressureRamp(channel, deflection);
      return;
    }
    this.pressureState.deflection = deflection;
    this.emitPressureState();
  }

  stopPressureRamp(): void {
    this.pressureGeneration += 1;
    this.pressureState.activeChannel = null;
    this.pressureState.deflection = 0;
    this.pressureState.ratePerSecond = 0;
    this.pressureState.step = 1;
    this.emitPressureState();
  }

  async reducePressure(channel: MilkPressureChannel, amount: number): Promise<void> {
    this.requireRunning();
    this.requirePressureAdjustmentAllowed(channel);
    assertInteger(amount, 1, PROTOCOL_PRESSURE_MAX, "减压步长");
    this.stopPressureRamp();
    const current = this.getChannelPressure(channel);
    await this.writeChannelPressure(channel, Math.max(0, current - amount), `quick-reduce-${amount}`);
  }

  async zeroPressure(channel: MilkPressureChannel): Promise<void> {
    this.requireRunning();
    this.requirePressureAdjustmentAllowed(channel);
    this.stopPressureRamp();
    await this.writeChannelPressure(channel, 0, "channel-zero");
  }

  async holdSuction(options: MilkSuctionHoldOptions = {useFixedPressure: true, fixedPressure: 20}): Promise<void> {
    this.requireRunning();
    if (this.suctionHoldActive) return;
    assertInteger(options.fixedPressure, 0, PROTOCOL_PRESSURE_MAX, "持续只吸固定强度");
    this.stopPressureRamp();
    this.suctionHoldRestoreConfig = {...this.cycle};
    this.suctionHoldUsesFixedPressure = options.useFixedPressure;

    // Every M transition starts with a complete Y/P/S/C/cycle-M snapshot.
    // The firmware must then enter hold-suction before its dedicated fixed
    // target is applied.
    await this.synchronizeCycleState(this.cycle, this.cycleMode, MILK_RUN_FLAG, "milk:hold-suction-sync");
    await this.sendOperation(MilkOperation.HoldSuction, this.cycle.suctionPressure, "milk:hold-suction");
    this.suctionHoldActive = true;
    this.motionMode = "hold-suction";
    this.emitDemoStatus(MilkOperation.HoldSuction, this.cycle.suctionPressure);
    if (options.useFixedPressure) {
      await this.sendOperation(MilkOperation.SetPressureY, options.fixedPressure, "milk:hold-suction-fixed-pressure");
      this.pressureState.suctionPressure = options.fixedPressure;
      this.emitPressureState();
      this.emitDemoStatus(MilkOperation.HoldSuction, options.fixedPressure);
    }
  }

  async releaseSuctionHold(): Promise<void> {
    this.requireRunning();
    if (!this.suctionHoldActive) return;
    await this.restoreAfterSuctionHold(this.cycleMode, "milk:release-suction-hold");
  }

  async setSuctionHoldFixedPressure(pressure: number): Promise<void> {
    this.requireRunning();
    if (!this.suctionHoldActive || !this.suctionHoldUsesFixedPressure) {
      throw new Error("持续只吸尚未以固定强度运行");
    }
    assertInteger(pressure, 0, PROTOCOL_PRESSURE_MAX, "持续只吸固定强度");
    await this.sendOperation(MilkOperation.SetPressureY, pressure, "milk:update-hold-suction-fixed-pressure");
    this.pressureState.suctionPressure = pressure;
    this.emitPressureState();
    this.emitDemoStatus(MilkOperation.HoldSuction, pressure);
  }

  async resumePulse(): Promise<void> {
    this.requireRunning();
    if (this.suctionHoldActive) {
      await this.restoreAfterSuctionHold(this.cycleMode, "milk:resume-pulse");
      return;
    }
    await this.synchronizeCycleState(this.cycle, this.cycleMode, MILK_RUN_FLAG, "milk:resume-pulse-sync");
    await this.sendOperation(MilkOperation.RunPulse, this.cycle.suctionPressure, "milk:resume-pulse");
    this.motionMode = "pulse";
    this.suctionHoldActive = false;
    this.emitDemoStatus(this.cycleMode === "extract" ? 1 : 2, this.cycle.suctionPressure);
  }

  async pause(): Promise<void> {
    this.requireRunning();
    this.stopPressureRamp();

    if (this.suctionHoldActive) {
      // Pausing directly in hold-suction leaves some firmware revisions with
      // stale Y/P values. Return to pulse first, restore the pre-hold snapshot,
      // and only then apply pause.
      const config = this.suctionHoldRestoreConfig ? {...this.suctionHoldRestoreConfig} : {...this.cycle};
      await this.sendOperation(MilkOperation.RunPulse, config.suctionPressure, "milk:pause-leave-hold-suction");
      await this.synchronizeCycleState(
        config,
        this.cycleMode,
        MILK_RUN_FLAG,
        "milk:pause-sync",
        {finalPauseFlag: MILK_PAUSE_FLAG},
      );
      this.cycle = config;
      this.setPressureValues(config.suctionPressure, config.blowPower);
      this.motionMode = "pulse";
      this.suctionHoldActive = false;
      this.suctionHoldUsesFixedPressure = false;
      this.suctionHoldRestoreConfig = null;
    } else {
      await this.synchronizeCycleState(
        this.cycle,
        this.cycleMode,
        MILK_RUN_FLAG,
        "milk:pause-sync",
        {finalPauseFlag: MILK_PAUSE_FLAG},
      );
    }
    this.paused = true;
  }

  async resume(): Promise<void> {
    this.requireStarted();
    if (!this.paused) return;
    await this.synchronizeCycleState(
      this.cycle,
      this.cycleMode,
      MILK_PAUSE_FLAG,
      "milk:resume-sync",
      {finalPauseFlag: MILK_RUN_FLAG},
    );
    this.paused = false;
  }

  async resumeWithCycleSync(config: MilkCycleConfig): Promise<void> {
    this.validateCycle(config);
    if (!this.paused) return;
    await this.synchronizeCycleState(
      config,
      this.cycleMode,
      MILK_PAUSE_FLAG,
      "milk:resume-with-cycle-sync",
      {finalPauseFlag: MILK_RUN_FLAG},
    );
    this.cycle = {...config};
    this.setPressureValues(config.suctionPressure, config.blowPower);
    this.paused = false;
  }

  async selectEdgeCycle(): Promise<void> {
    this.requireRunning();
    if (this.suctionHoldActive) await this.restoreAfterSuctionHold("edge", "milk:switch-from-hold-to-edge");
    else await this.selectCycle("edge");
  }

  async selectExtractCycle(): Promise<void> {
    this.requireRunning();
    if (this.suctionHoldActive) await this.restoreAfterSuctionHold("extract", "milk:switch-from-hold-to-extract");
    else await this.selectCycle("extract");
  }

  async emergencyStop(reason = "紧急停止"): Promise<void> {
    this.stopPressureRamp();
    const wasHoldingSuction = this.suctionHoldActive;
    this.running = this.connected;
    this.paused = true;
    this.motionMode = "pulse";
    this.suctionHoldActive = false;
    this.suctionHoldUsesFixedPressure = false;
    this.suctionHoldRestoreConfig = null;
    if (!this.connected) return;

    this.emitLog("INFO", "emergency-stop", undefined, reason);
    const selectedCycleOperation = this.cycleMode === "extract"
      ? MilkOperation.SelectExtractCycle
      : MilkOperation.SelectEdgeCycle;
    const frames: ReadonlyArray<readonly [number, number, number, string]> = [
      ...(wasHoldingSuction
        ? [[4, MilkOperation.RunPulse, 0, "stop:leave-hold-suction-before-pause"]] as const
        : []),
      [1, MILK_PAUSE_FLAG, 0, "stop:pause-and-zero-blow-pwm"],
      [4, MilkOperation.SetPressureY, 0, "stop:zero-suction-pressure"],
      [2, 0, 0, "stop:reset-suction-duration"],
      [3, 0, 0, "stop:reset-phase-delta"],
      [4, selectedCycleOperation, 0, "stop:sync-cycle-mode"],
      [1, MILK_PAUSE_FLAG, 0, "stop:enter-pause"],
    ];

    let successfulWrites = 0;
    for (const [id, high, low, label] of frames) {
      try {
        await this.sendFrame(id, high, low, label);
        successfulWrites += 1;
      } catch {
        // Continue: every remaining zero-output frame is still worth attempting.
      }
    }
    if (successfulWrites !== frames.length) {
      throw new Error(`安全停机仅完成 ${successfulWrites}/${frames.length} 个写入；请立即使用物理急停`);
    }
    this.setPressureValues(0, 0);
    this.cycle.suctionMs = MILK_SUCTION_MAX_MS;
    this.cycle.secondPhaseMs = MILK_SUCTION_MAX_MS;
    this.emitDemoStatus(this.cycleMode === "extract" ? 1 : 2, 0);
  }

  async setPressureTargets(suctionPressure: number, blowPower: number): Promise<void> {
    this.requireRunning();
    this.requireSuctionHoldReleased();
    assertInteger(suctionPressure, 0, PROTOCOL_PRESSURE_MAX, "吸气压力");
    assertInteger(blowPower, 0, PROTOCOL_PRESSURE_MAX, "吹气 PWM 功率");
    this.stopPressureRamp();
    if (suctionPressure !== this.pressureState.suctionPressure) {
      await this.writeChannelPressure("suction", suctionPressure, "memory-restore-direct");
    }
    if (blowPower !== this.pressureState.blowPower) {
      await this.writeChannelPressure("blow", blowPower, "memory-restore-direct");
    }
  }

  async sendManualFrame(id: number, high: number, low: number): Promise<void> {
    this.requireConnected();
    assertInteger(id, 0, 0xff, "指令 ID");
    assertInteger(high, 0, 0xff, "高位参数");
    assertInteger(low, 0, 0xff, "低位参数");
    await this.sendFrame(id, high, low, `manual:id-${id}`);
  }

  protected handleNotify(data: DataView): void {
    if (data.byteLength < 3) {
      this.reportFault(`Milk 通知长度不足：${data.byteLength}`);
      return;
    }
    const type = data.getUint8(1);
    const suctionPressure = data.getUint8(2);
    const raw = Array.from(new Uint8Array(data.buffer, data.byteOffset, data.byteLength));
    const status: MilkStatus = {raw, type, suctionPressure, label: STATUS_LABELS[type] ?? "未知"};

    // Notifications are partial state updates, not complete snapshots:
    // 1/2 report the selected cycle, while 4/5 report the motion form.
    // Neither dimension carries the pause flag, so preserve the current pause
    // state and merge only the state represented by this notification.
    switch (type) {
      case 1:
        this.cycleMode = "extract";
        break;
      case 2:
        this.cycleMode = "edge";
        break;
      case 4:
        if (!this.suctionHoldActive) this.stopPressureRamp();
        this.motionMode = "hold-suction";
        this.suctionHoldActive = true;
        break;
      case 5:
        this.motionMode = "pulse";
        this.suctionHoldActive = false;
        break;
    }

    this.statusListeners.forEach((listener) => listener(status));
  }

  protected override async afterConnect(): Promise<void> {
    await this.emergencyStop("连接后重置并暂停");
  }

  protected override async beforeDisconnect(): Promise<void> {
    await this.emergencyStop("断开连接前停机");
  }

  protected override onConnectionClosed(): void {
    this.stopPressureRamp();
    this.running = false;
    this.paused = false;
    this.motionMode = "pulse";
    this.suctionHoldActive = false;
    this.suctionHoldUsesFixedPressure = false;
    this.suctionHoldRestoreConfig = null;
    this.setPressureValues(0, 0);
  }

  protected override onHeartbeatFailure(): void {
    if (!this.running) return;
    this.stopPressureRamp();
    this.running = this.connected;
    this.paused = true;
    this.suctionHoldActive = false;
    this.motionMode = "pulse";
    this.suctionHoldUsesFixedPressure = false;
    this.suctionHoldRestoreConfig = null;
    this.setPressureValues(0, 0);
    this.emitLog("INFO", "heartbeat-watchdog-stop", undefined, "心跳发送失败；设备会自动停机，本地状态已重置为 pause");
    this.reportFault("Milk 心跳丢失；设备已进入自动停机，本地状态已重置为 pause，建议重新连接");
  }

  private async setSuctionDuration(milliseconds: number): Promise<void> {
    assertInteger(milliseconds, 0, MILK_SUCTION_MAX_MS, "吸气时长 S");
    // 蓝牙协议发送反向值 S' = 999 - S，界面展示实机使用的 S。
    const protocolValue = MILK_SUCTION_MAX_MS - milliseconds;
    const [high, low] = encodeUint16BE(protocolValue);
    await this.sendFrame(2, high, low, "milk:set-suction-duration");
  }

  private async setPhaseDelta(milliseconds: number): Promise<void> {
    // 固件未规定 C 的业务范围；线上字段仍受有符号 16 位编码限制。
    assertInteger(milliseconds, MILK_PHASE_DELTA_MIN, MILK_PHASE_DELTA_MAX, "阶段差 C");
    const [high, low] = encodeInt16BE(milliseconds);
    await this.sendFrame(3, high, low, "milk:set-phase-delta");
  }

  private async runPressureRamp(generation: number): Promise<void> {
    while (
      generation === this.pressureGeneration
      && this.running
      && this.connected
      && this.pressureState.activeChannel !== null
    ) {
      const channel = this.pressureState.activeChannel;
      const deflection = this.pressureState.deflection;
      const magnitude = Math.abs(deflection);

      if (magnitude <= PRESSURE_DEAD_ZONE) {
        this.pressureState.ratePerSecond = 0;
        this.pressureState.step = 1;
        this.emitPressureState();
        await this.delay(50);
        continue;
      }

      const direction = deflection > 0 ? 1 : -1;
      const current = this.getChannelPressure(channel);
      const normalized = Math.min(1, (magnitude - PRESSURE_DEAD_ZONE) / (1 - PRESSURE_DEAD_ZONE));
      const profile = this.getRampProfile(channel, current, direction, normalized);
      let next = current + direction * profile.step;
      next = Math.max(0, Math.min(PROTOCOL_PRESSURE_MAX, next));

      if (channel === "blow" && direction > 0) {
        if (current < 20 && next > 20) next = 20;
        if (current < 30 && next > 30) next = 30;
      }
      if (channel === "suction" && direction > 0 && current < 60 && next > 60) next = 60;

      if (next === current) {
        this.stopPressureRamp();
        return;
      }

      const actualStep = Math.abs(next - current);
      this.pressureState.ratePerSecond = direction * profile.ratePerSecond;
      this.pressureState.step = actualStep;
      this.emitPressureState();

      const startedAt = performance.now();
      await this.writeChannelPressure(channel, next, "ramp");
      if (generation !== this.pressureGeneration) return;
      const intervalMs = (actualStep / profile.ratePerSecond) * 1_000;
      const remainingMs = Math.max(0, intervalMs - (performance.now() - startedAt));
      if (remainingMs > 0) await this.delay(remainingMs);
    }
  }

  private getRampProfile(
    channel: MilkPressureChannel,
    current: number,
    direction: 1 | -1,
    normalized: number,
  ): {ratePerSecond: number; step: number} {
    if (direction < 0) {
      return {
        ratePerSecond: 1 + 19 * normalized,
        step: normalized >= 0.6 ? 2 : 1,
      };
    }

    if (channel === "suction") {
      const maximumRate = current < 60 ? 20 : 5;
      return {ratePerSecond: 1 + (maximumRate - 1) * normalized, step: 1};
    }

    // Select the rate of the region being entered: 19 -> 20 already uses
    // 5 units/s, and 30 -> 31 already uses 3 units/s.
    const maximumRate = current < 19 ? 20 : current < 30 ? 5 : 3;
    return {
      ratePerSecond: 1 + (maximumRate - 1) * normalized,
      step: normalized >= 0.6 ? 2 : 1,
    };
  }

  private async writeChannelPressure(channel: MilkPressureChannel, pressure: number, reason: string): Promise<void> {
    this.requirePressureAdjustmentAllowed(channel);
    assertInteger(pressure, 0, PROTOCOL_PRESSURE_MAX, `${channel} pressure`);
    if (channel === "suction") {
      await this.sendOperation(MilkOperation.SetPressureY, pressure, `pressure:suction-y:${reason}`);
      this.pressureState.suctionPressure = pressure;
      this.cycle.suctionPressure = pressure;
      if (this.suctionHoldActive && this.suctionHoldRestoreConfig) {
        this.suctionHoldRestoreConfig.suctionPressure = pressure;
      }
    } else {
      await this.sendFrame(1, MILK_RUN_FLAG, pressure, `pressure:blow-pwm:${reason}`);
      this.pressureState.blowPower = pressure;
      this.cycle.blowPower = pressure;
    }
    this.emitPressureState();
    this.emitDemoStatus(
      this.suctionHoldActive ? MilkOperation.HoldSuction : this.cycleMode === "extract" ? 1 : 2,
      this.cycle.suctionPressure,
    );
  }

  private emitDemoStatus(type: number, pressure: number): void {
    if (!this.isDemoMode) return;
    const bytes = [0xff, type, pressure, 0xfe];
    this.emitLog("RX", "SIM notification", bytes);
    const data = Uint8Array.from(bytes);
    this.handleNotify(new DataView(data.buffer));
  }

  private getChannelPressure(channel: MilkPressureChannel): number {
    return channel === "suction" ? this.pressureState.suctionPressure : this.pressureState.blowPower;
  }

  private setPressureValues(suction: number, blow: number): void {
    this.pressureState.suctionPressure = suction;
    this.pressureState.blowPower = blow;
    this.cycle.suctionPressure = suction;
    this.cycle.blowPower = blow;
    this.emitPressureState();
  }

  private emitPressureState(): void {
    const state = this.currentPressure;
    this.pressureListeners.forEach((listener) => listener(state));
  }

  private assertDeflection(deflection: number): void {
    if (!Number.isFinite(deflection) || deflection < -1 || deflection > 1) {
      throw new RangeError("滑块偏移必须在 -1 到 1 之间");
    }
  }

  private requireSuctionHoldReleased(): void {
    if (this.suctionHoldActive) {
      throw new Error("持续只吸已暂停其他运行状态；请先取消持续只吸或停止设备");
    }
  }

  private requirePressureAdjustmentAllowed(channel: MilkPressureChannel): void {
    if (this.suctionHoldActive && this.suctionHoldUsesFixedPressure && channel === "suction") {
      throw new Error("持续只吸正在使用固定强度；请先取消持续只吸或关闭固定强度");
    }
    if (this.suctionHoldActive && channel !== "suction") {
      throw new Error("持续只吸期间只能调整吸气压力 Y");
    }
  }

  private async sendOperation(operation: MilkOperation, value: number, label: string): Promise<void> {
    assertInteger(operation, 0, 0xff, "operation");
    assertInteger(value, 0, PROTOCOL_PRESSURE_MAX, "operation value");
    await this.sendFrame(4, operation, value, label);
  }

  private async restoreAfterSuctionHold(mode: MilkCycleMode, label: string): Promise<void> {
    const config = this.suctionHoldRestoreConfig ? {...this.suctionHoldRestoreConfig} : {...this.cycle};

    // Leaving hold-suction is a full device-state synchronization. This avoids
    // inheriting the fixed hold pressure or any stale timing/PWM value.
    await this.synchronizeCycleState(config, mode, MILK_RUN_FLAG, `${label}:sync`);
    await this.sendOperation(MilkOperation.RunPulse, config.suctionPressure, `${label}:run-pulse`);

    this.cycle = config;
    this.cycleMode = mode;
    this.pressureState.suctionPressure = config.suctionPressure;
    this.pressureState.blowPower = config.blowPower;
    this.suctionHoldActive = false;
    this.suctionHoldUsesFixedPressure = false;
    this.suctionHoldRestoreConfig = null;
    this.motionMode = "pulse";
    this.emitPressureState();
    this.emitDemoStatus(mode === "extract" ? 1 : 2, config.suctionPressure);
  }

  private async selectCycle(mode: MilkCycleMode): Promise<void> {
    this.requireReady();
    await this.synchronizeCycleState(this.cycle, mode, this.paused ? MILK_PAUSE_FLAG : MILK_RUN_FLAG, `milk:select-${mode}-sync`);
    this.cycleMode = mode;
    this.emitDemoStatus(mode === "extract" ? 1 : 2, this.cycle.suctionPressure);
  }

  private async synchronizeCycleState(
    config: MilkCycleConfig,
    mode: MilkCycleMode,
    pauseFlag: MilkPauseFlag,
    label: string,
    options: {assertActive?: () => void; finalPauseFlag?: MilkPauseFlag} = {},
  ): Promise<void> {
    this.validateCycle(config);
    const assertActive = options.assertActive ?? (() => undefined);
    const operation = mode === "extract"
      ? MilkOperation.SelectExtractCycle
      : MilkOperation.SelectEdgeCycle;

    // Y, P (+ pause), S, C and M are deliberately all rewritten. Mode and
    // pause transitions must never depend on firmware-side cached fields.
    await this.sendOperation(MilkOperation.SetPressureY, config.suctionPressure, `${label}:suction-pressure-y`);
    assertActive();
    await this.sendFrame(1, pauseFlag, config.blowPower, `${label}:blow-power-and-pause`);
    assertActive();
    await this.setSuctionDuration(config.suctionMs);
    assertActive();
    await this.setPhaseDelta(config.suctionMs - config.secondPhaseMs);
    assertActive();
    await this.sendOperation(operation, config.suctionPressure, `${label}:cycle-mode-m`);
    assertActive();
    if (options.finalPauseFlag !== undefined) {
      await this.sendFrame(1, options.finalPauseFlag, config.blowPower, `${label}:final-pause-state`);
      assertActive();
    }
  }

  private validateCycle(config: MilkCycleConfig): void {
    assertInteger(config.suctionPressure, 0, PROTOCOL_PRESSURE_MAX, "吸气压力");
    assertInteger(config.blowPower, 0, PROTOCOL_PRESSURE_MAX, "吹气 PWM 功率");
    assertInteger(config.suctionMs, 0, MILK_SUCTION_MAX_MS, "吸气时长");
    assertInteger(config.secondPhaseMs, -MILK_PHASE_DELTA_MAX, MILK_SUCTION_MAX_MS - MILK_PHASE_DELTA_MIN, "第二阶段时长");
    assertInteger(config.suctionMs - config.secondPhaseMs, MILK_PHASE_DELTA_MIN, MILK_PHASE_DELTA_MAX, "阶段差 C");
  }

  private requireReady(): void {
    this.requireConnected();
  }

  private requireConnected(): void {
    if (!this.connected) throw new Error("设备未连接");
  }

  private requireStarted(): void {
    this.requireReady();
    if (!this.running) throw new Error("设备尚未运行");
  }

  private requireRunning(): void {
    this.requireStarted();
    if (this.paused) throw new Error("设备已暂停；请先继续运行");
  }

}
