import type {MemorySettings} from "./memory-store";
import type {BandPoint, BandRecord, BandTransitionType} from "./band-store";

export type BandPlayerState = "idle" | "starting" | "ramping" | "dwelling" | "jumping" | "paused";

export interface BandFrame {
  mode: BandPoint["mode"];
  settings: MemorySettings;
}

export interface BandPlayerSnapshot {
  state: BandPlayerState;
  bandName: string | null;
  pointIndex: number;
  pointCount: number;
  pointName: string | null;
  targetName: string | null;
  transitionType: BandTransitionType | null;
  round: number;
  totalRounds: number | null;
  remainingMs: number;
  progress: number;
  currentFrame: BandFrame | null;
  targetPoint: BandPoint | null;
}

interface BandPlayerDependencies {
  prepare(): Promise<void>;
  applyFrame(frame: BandFrame, complete: boolean, assertActive: () => void): Promise<void>;
  finished(reason: string, error?: unknown): void;
  changed(): void;
}

class BandCancelledError extends Error {}

const UPDATE_INTERVAL_MS = 250;

function interpolate(start: number, end: number, progress: number): number {
  return Math.round(start + (end - start) * progress);
}

function frameForPoint(point: BandPoint): BandFrame {
  return {mode: point.mode, settings: {...point.settings}};
}

function interpolateFrame(start: BandFrame, target: BandPoint, progress: number, mode: BandFrame["mode"]): BandFrame {
  const startSecond = start.settings.secondPhaseMs;
  const targetSecond = target.settings.secondPhaseMs;
  const suctionMs = interpolate(start.settings.suctionMs, target.settings.suctionMs, progress);
  const secondPhaseMs = interpolate(startSecond, targetSecond, progress);
  return {
    mode,
    settings: {
      suctionPressure: interpolate(start.settings.suctionPressure, target.settings.suctionPressure, progress),
      blowPower: interpolate(start.settings.blowPower, target.settings.blowPower, progress),
      suctionMs,
      secondPhaseMs,
    },
  };
}

export class BandPlayer {
  private state: BandPlayerState = "idle";
  private band: BandRecord | null = null;
  private pointId: string | null = null;
  private pointIndex = -1;
  private round = 0;
  private remainingMs = 0;
  private progress = 0;
  private currentFrame: BandFrame | null = null;
  private generation = 0;
  private revision = 0;
  private observedRevision = 0;
  private pauseRequested = false;
  private skipRequested = false;
  private interruptWait: (() => void) | null = null;
  private resumeWait: (() => void) | null = null;

  constructor(private readonly dependencies: BandPlayerDependencies) {}

  get active(): boolean {
    return this.state !== "idle";
  }

  get paused(): boolean {
    return this.state === "paused";
  }

  get snapshot(): BandPlayerSnapshot {
    const source = this.currentSource();
    const target = this.currentTarget();
    return {
      state: this.state,
      bandName: this.band?.name ?? null,
      pointIndex: this.pointIndex,
      pointCount: this.band?.points.length ?? 0,
      pointName: source?.name ?? null,
      targetName: target?.name ?? null,
      transitionType: source?.toNext.type ?? null,
      round: this.round,
      totalRounds: this.band?.repeat.mode === "count" ? this.band.repeat.rounds : null,
      remainingMs: this.remainingMs,
      progress: this.progress,
      currentFrame: this.currentFrame ? structuredClone(this.currentFrame) : null,
      targetPoint: target ? structuredClone(target) : null,
    };
  }

  start(band: BandRecord): void {
    if (this.active) throw new Error("已有波段正在运行");
    this.band = structuredClone(band);
    this.pointIndex = 0;
    this.pointId = this.band.points[0]?.id ?? null;
    this.round = 1;
    this.remainingMs = 0;
    this.progress = 0;
    this.currentFrame = null;
    this.pauseRequested = false;
    this.skipRequested = false;
    this.observedRevision = this.revision;
    const generation = ++this.generation;
    this.setState("starting");
    void this.run(generation);
  }

  updateBand(band: BandRecord): void {
    if (!this.active) throw new Error("当前没有正在运行的波段");
    if (!this.pointId || !band.points.some((point) => point.id === this.pointId)) {
      throw new Error("运行中的当前参数点不能删除");
    }
    this.band = structuredClone(band);
    this.pointIndex = this.band.points.findIndex((point) => point.id === this.pointId);
    this.revision += 1;
    this.interruptWait?.();
    this.dependencies.changed();
  }

  hold(): void {
    if (!this.active || this.paused) return;
    this.pauseRequested = true;
    this.interruptWait?.();
    this.dependencies.changed();
  }

  resume(): void {
    if (!this.paused) return;
    this.pauseRequested = false;
    this.resumeWait?.();
    this.resumeWait = null;
  }

  skip(): void {
    if (!this.active) return;
    this.skipRequested = true;
    if (this.paused) {
      this.pauseRequested = false;
      this.resumeWait?.();
      this.resumeWait = null;
      return;
    }
    this.interruptWait?.();
  }

  cancel(): boolean {
    const wasActive = this.active;
    this.generation += 1;
    this.interruptWait?.();
    this.resumeWait?.();
    this.interruptWait = null;
    this.resumeWait = null;
    this.band = null;
    this.pointId = null;
    this.pointIndex = -1;
    this.round = 0;
    this.remainingMs = 0;
    this.progress = 0;
    this.currentFrame = null;
    this.pauseRequested = false;
    this.skipRequested = false;
    this.setState("idle");
    return wasActive;
  }

  private async run(generation: number): Promise<void> {
    try {
      await this.dependencies.prepare();
      this.assertActive(generation);
      const first = this.currentSource();
      if (!first) throw new Error("波段起始参数点不存在");
      this.currentFrame = frameForPoint(first);

      while (true) {
        this.assertActive(generation);
        const source = this.currentSource();
        if (!source) throw new Error("波段当前参数点不存在");
        await this.runSegment(generation, source);
        this.assertActive(generation);

        const target = this.currentTarget();
        if (!target) throw new Error("波段目标参数点不存在");
        const wrapped = this.band?.points[0]?.id === target.id;
        this.pointId = target.id;
        this.pointIndex = this.band?.points.findIndex((point) => point.id === target.id) ?? -1;
        this.progress = 0;
        this.dependencies.changed();
        if (wrapped) {
          if (this.band?.repeat.mode === "count" && this.round >= this.band.repeat.rounds) break;
          this.round += 1;
        }
      }
      this.assertActive(generation);
      this.dependencies.finished("波段播放完成");
    } catch (error) {
      if (error instanceof BandCancelledError || generation !== this.generation) return;
      this.dependencies.finished("波段播放失败", error);
    }
  }

  private async runSegment(generation: number, initialSource: BandPoint): Promise<void> {
    let anchor = this.currentFrame ?? frameForPoint(initialSource);
    let duration = initialSource.toNext.durationMs;
    let elapsedBeforeAnchor = 0;
    let anchorStartedAt = performance.now();
    this.observedRevision = this.revision;

    // Entering every segment is a synchronization boundary. The complete
    // current point (its Y/P/S/C and its own M) is always rewritten here.
    anchor = {...anchor, mode: initialSource.mode};
    this.currentFrame = structuredClone(anchor);
    await this.dependencies.applyFrame(this.currentFrame, true, () => this.assertActive(generation));

    while (true) {
      this.assertActive(generation);
      if (this.pauseRequested) {
        const pausedAt = performance.now();
        this.setState("paused");
        await new Promise<void>((resolve) => { this.resumeWait = resolve; });
        this.resumeWait = null;
        this.assertActive(generation);
        anchorStartedAt += performance.now() - pausedAt;
        continue;
      }

      const source = this.currentSource();
      const target = this.currentTarget();
      if (!source || !target) throw new Error("运行中的波段结构无效");

      if (this.observedRevision !== this.revision) {
        const elapsed = Math.min(duration, elapsedBeforeAnchor + Math.max(0, performance.now() - anchorStartedAt));
        anchor = this.currentFrame ?? anchor;
        duration = source.toNext.durationMs;
        elapsedBeforeAnchor = Math.min(duration, elapsed);
        anchorStartedAt = performance.now();
        this.observedRevision = this.revision;
      }

      if (this.currentFrame && this.currentFrame.mode !== source.mode) {
        this.currentFrame = {...this.currentFrame, mode: source.mode};
        anchor = {...anchor, mode: source.mode};
        await this.dependencies.applyFrame(this.currentFrame, true, () => this.assertActive(generation));
      }

      const transition = source.toNext;
      const elapsed = transition.type === "jump"
        ? 0
        : Math.min(duration, elapsedBeforeAnchor + Math.max(0, performance.now() - anchorStartedAt));
      this.remainingMs = transition.type === "jump" ? 0 : Math.max(0, duration - elapsed);
      this.progress = transition.type === "jump" ? 1 : duration > 0 ? elapsed / duration : 1;

      if (this.skipRequested || transition.type === "jump" || this.remainingMs <= 0) {
        this.skipRequested = false;
        this.setState("jumping");
        this.currentFrame = {mode: source.mode, settings: {...target.settings}};
        await this.dependencies.applyFrame(this.currentFrame, true, () => this.assertActive(generation));
        this.remainingMs = 0;
        this.progress = 1;
        return;
      }

      const mode: BandFrame["mode"] = source.mode;
      if (transition.type === "ramp") {
        this.setState("ramping");
        const anchorRemaining = Math.max(1, duration - elapsedBeforeAnchor);
        const anchorProgress = Math.min(1, Math.max(0, (performance.now() - anchorStartedAt) / anchorRemaining));
        this.currentFrame = interpolateFrame(anchor, target, anchorProgress, mode);
        await this.dependencies.applyFrame(this.currentFrame, false, () => this.assertActive(generation));
      } else {
        this.setState("dwelling");
        if (this.currentFrame && this.currentFrame.mode !== mode) {
          this.currentFrame = {...this.currentFrame, mode};
          await this.dependencies.applyFrame(this.currentFrame, false, () => this.assertActive(generation));
        }
      }
      this.dependencies.changed();
      await this.wait(Math.min(UPDATE_INTERVAL_MS, this.remainingMs));
    }
  }

  private wait(milliseconds: number): Promise<void> {
    return new Promise((resolve) => {
      const timer = window.setTimeout(() => {
        this.interruptWait = null;
        resolve();
      }, milliseconds);
      this.interruptWait = () => {
        window.clearTimeout(timer);
        this.interruptWait = null;
        resolve();
      };
    });
  }

  private currentSource(): BandPoint | null {
    if (!this.band || !this.pointId) return null;
    return this.band.points.find((point) => point.id === this.pointId) ?? null;
  }

  private currentTarget(): BandPoint | null {
    const source = this.currentSource();
    if (!this.band || !source) return null;
    const index = this.band.points.findIndex((point) => point.id === source.id);
    return this.band.points[(index + 1) % this.band.points.length] ?? null;
  }

  private assertActive(generation: number): void {
    if (generation !== this.generation || !this.band) throw new BandCancelledError();
  }

  private setState(state: BandPlayerState): void {
    this.state = state;
    this.dependencies.changed();
  }
}
