function byId<T extends HTMLElement>(id: string): T {
  const element = document.getElementById(id);
  if (!element) throw new Error(`缺少页面元素 #${id}`);
  return element as T;
}

function initControlTabs(): void {
  const tabs = Array.from(document.querySelectorAll<HTMLButtonElement>(".control-tab"));
  const panels = Array.from(document.querySelectorAll<HTMLElement>(".control-tab-panel"));

  const activate = (tab: HTMLButtonElement, moveFocus = false): void => {
    for (const candidate of tabs) {
      const active = candidate === tab;
      candidate.setAttribute("aria-selected", String(active));
      candidate.tabIndex = active ? 0 : -1;
    }
    for (const panel of panels) panel.hidden = panel.id !== tab.getAttribute("aria-controls");
    if (moveFocus) tab.focus();
    try {
      localStorage.setItem(CONTROL_TAB_KEY, tab.id);
    } catch {
      // localStorage 可能在隐私模式下不可用；Tab 切换本身仍然有效。
    }
  };

  for (const [index, tab] of tabs.entries()) {
    tab.addEventListener("click", () => activate(tab));
    tab.addEventListener("keydown", (event) => {
      let nextIndex: number | null = null;
      if (event.key === "ArrowLeft") nextIndex = (index - 1 + tabs.length) % tabs.length;
      if (event.key === "ArrowRight") nextIndex = (index + 1) % tabs.length;
      if (event.key === "Home") nextIndex = 0;
      if (event.key === "End") nextIndex = tabs.length - 1;
      if (nextIndex === null) return;
      event.preventDefault();
      const nextTab = tabs[nextIndex];
      if (nextTab) activate(nextTab, true);
    });
  }

  let savedTabId: string | null = null;
  try {
    savedTabId = localStorage.getItem(CONTROL_TAB_KEY);
  } catch {
    // 使用默认的手动控制 Tab。
  }
  const defaultTab = tabs[0];
  if (!defaultTab) throw new Error("缺少控制模块 Tab");
  activate(tabs.find((tab) => tab.id === savedTabId) ?? defaultTab);
}

