function renderBandPlayback(): void {
  const snapshot = bandPlayer.snapshot;
  const labels = {idle: "未运行", starting: "正在启动", ramping: "渐变中", dwelling: "定时保持", jumping: "正在跳变", paused: "人工保持"} as const;
  const stateLabel = snapshot.state === "paused"
    ? bandPausedBySuctionHold ? "持续只吸" : bandPausedByDevicePause ? "设备暂停" : "人工保持"
    : labels[snapshot.state];
  ui.bandState.textContent = stateLabel;
  ui.bandState.className = `mode-pill${snapshot.state === "paused" ? " band-state-paused" : ""}`;
  if (snapshot.state === "idle") {
    ui.bandNowLabel.textContent = bandDraft.points.length >= 2 ? `已编排 ${bandDraft.points.length} 个参数点。` : "编排至少两个有效参数点后即可启动。";
    ui.bandNextLabel.textContent = "运行中修改参数和时间会同步到当前播放实例。";
    ui.bandRemaining.textContent = "—";
    ui.bandCurrentFrame.hidden = true;
    ui.bandProgressBar.style.width = "0%";
    return;
  }
  const round = snapshot.totalRounds === null ? `第 ${snapshot.round} 轮` : `第 ${snapshot.round}/${snapshot.totalRounds} 轮`;
  ui.bandNowLabel.textContent = `${round} · 点 ${snapshot.pointIndex + 1}/${snapshot.pointCount} · ${snapshot.pointName ?? "准备设备"}`;
  ui.bandNextLabel.textContent = snapshot.targetName ? `${snapshot.transitionType ? bandTransitionLabel(snapshot.transitionType) : "准备"} → ${snapshot.targetName}` : "正在准备起始点";
  ui.bandRemaining.textContent = snapshot.state === "starting" || snapshot.state === "jumping" ? "切换中" : `${(snapshot.remainingMs / 1_000).toFixed(1)} 秒`;
  const frame = snapshot.currentFrame;
  ui.bandCurrentFrame.hidden = frame === null;
  if (frame) {
    const displayedSettings = constrainedConfig(frame.settings);
    const delta = displayedSettings.suctionMs - displayedSettings.secondPhaseMs;
    ui.bandCurrentMode.textContent = `${stateLabel} · ${MODE_LABELS[frame.mode]}`;
    ui.bandCurrentY.textContent = String(displayedSettings.suctionPressure);
    ui.bandCurrentP.textContent = String(displayedSettings.blowPower);
    ui.bandCurrentS.textContent = `${displayedSettings.suctionMs} ms`;
    ui.bandCurrentC.textContent = `${delta > 0 ? "+" : ""}${delta} ms`;
  }
  const target = snapshot.targetPoint;
  const targetSettings = target ? constrainedConfig(target.settings) : null;
  ui.bandTargetValues.textContent = targetSettings
    ? `${targetSettings.suctionPressure} / ${targetSettings.blowPower} / ${targetSettings.suctionMs} / ${targetSettings.suctionMs - targetSettings.secondPhaseMs}`
    : "—";
  ui.bandProgressBar.style.width = `${Math.max(0, Math.min(1, snapshot.progress)) * 100}%`;
}

function terminateBand(reason: string, error?: unknown): Promise<void> {
  if (bandTermination) return bandTermination;
  bandPlayer.cancel();
  bandPausedByDevicePause = false;
  bandPausedBySuctionHold = false;
  resetSpringControls();
  controller.stopPressureRamp();
  renderState();
  bandTermination = (async () => {
    try {
      await controller.emergencyStop(reason);
      resetTimingParameters();
      showMessage(error === undefined
        ? `${reason}；波段已终止，设备已归零并暂停。`
        : `${reason}：${errorMessage(error)}。波段已终止，设备已归零并暂停。`, error !== undefined, error !== undefined);
    } catch (stopError) {
      showMessage(`${reason}；波段已终止，但归零写入失败：${errorMessage(stopError)}。请立即使用物理急停。`, true, true);
    } finally {
      bandTermination = null;
      renderBandEditor();
      renderBandPlayback();
      renderState();
    }
  })();
  return bandTermination;
}

function terminateActivePlayback(reason: string, error?: unknown): Promise<void> {
  return bandPlayer.active ? terminateBand(reason, error) : terminateSequence(reason, error);
}

async function waitForBandPause(): Promise<void> {
  const deadline = performance.now() + 5_000;
  while (bandPlayer.active && !bandPlayer.paused && performance.now() < deadline) {
    await new Promise<void>((resolve) => window.setTimeout(resolve, 20));
  }
  if (!bandPlayer.paused) throw new Error("波段未能及时进入保持状态");
}

