function persistBackgroundMode(enabled: boolean): void {
  try {
    localStorage.setItem(BACKGROUND_MODE_KEY, String(enabled));
  } catch {
    // The current session can still use the foreground service.
  }
}

function renderBackgroundMode(): void {
  ui.backgroundModeEnabled.checked = backgroundModeEnabled;
  ui.backgroundModeState.textContent = !isNativeBackgroundModeAvailable()
    ? "仅 Android App"
    : backgroundModeEnabled ? "后台服务运行中" : "未启用";
  ui.backgroundModeState.className = `mode-pill${backgroundModeEnabled ? " background-mode-active" : ""}`;
}

async function setBackgroundMode(enabled: boolean, announce = true): Promise<void> {
  if (!isNativeBackgroundModeAvailable()) return;
  ui.backgroundModeEnabled.disabled = true;
  try {
    if (enabled) await startNativeBackgroundMode();
    else await stopNativeBackgroundMode();
    backgroundModeEnabled = enabled;
    persistBackgroundMode(enabled);
    renderBackgroundMode();
    if (announce) {
      showMessage(enabled
        ? "Android 后台服务已启动；切到后台后将继续保持蓝牙通信和控制流程。"
        : "Android 后台服务已停止；App 进入后台时将自动安全停机。", false, true);
    }
  } catch (error) {
    ui.backgroundModeEnabled.checked = backgroundModeEnabled;
    showMessage(`无法${enabled ? "启动" : "停止"}后台服务：${errorMessage(error)}`, true, true);
  } finally {
    ui.backgroundModeEnabled.disabled = false;
  }
}

async function safelyStopForAppTermination(reason: string): Promise<void> {
  sequencePlayer.cancel();
  bandPlayer.cancel();
  resetSpringControls();
  controller.stopPressureRamp();
  if (!controller.connected) return;
  try {
    await controller.emergencyStop(reason);
    await controller.flushWrites();
  } catch (error) {
    console.error("App 终止前安全停机未完全执行", error);
  }
}

async function safelyExitAndroidApp(): Promise<void> {
  if (exitInProgress) return;
  exitInProgress = true;
  showMessage("正在归零压力与功率并安全退出……", false, true);
  try {
    await safelyStopForAppTermination("用户确认退出 App");
    await stopNativeBackgroundMode();
  } finally {
    await App.exitApp();
  }
}

async function initializeAndroidLifecycle(): Promise<void> {
  if (!isNativeBackgroundModeAvailable()) {
    ui.backgroundModeEnabled.disabled = true;
    renderBackgroundMode();
    return;
  }

  let savedEnabled = false;
  try {
    savedEnabled = localStorage.getItem(BACKGROUND_MODE_KEY) === "true";
  } catch {
    // Keep the default disabled state.
  }
  backgroundModeEnabled = savedEnabled;
  if (savedEnabled && !await nativeBackgroundModeIsRunning()) {
    try {
      await startNativeBackgroundMode();
    } catch (error) {
      backgroundModeEnabled = false;
      persistBackgroundMode(false);
      showMessage(`后台服务自动恢复失败：${errorMessage(error)}`, true, true);
    }
  }
  renderBackgroundMode();

  await onNativeTaskRemoved(() => {
    void safelyStopForAppTermination("App 已从最近任务中终止");
  });
  await App.addListener("backButton", () => {
    if (exitInProgress) return;
    const now = Date.now();
    if (now - lastBackPressedAt > DOUBLE_BACK_WINDOW_MS) {
      lastBackPressedAt = now;
      showMessage("再次按下返回键以打开退出确认窗口。", false, true);
      return;
    }
    lastBackPressedAt = 0;
    if (window.confirm("确定要退出 Milk Controller 吗？\n\n确认后将先归零压力与功率、暂停设备，然后退出 App。")) {
      void safelyExitAndroidApp();
    }
  });
}

