export function clampInteger(value: number, minimum: number, maximum: number, name: string): number {
  if (!Number.isFinite(value)) throw new RangeError(`${name} 必须是有限数字`);
  return Math.min(maximum, Math.max(minimum, Math.round(value)));
}

export function assertInteger(value: number, minimum: number, maximum: number, name: string): void {
  if (!Number.isInteger(value) || value < minimum || value > maximum) {
    throw new RangeError(`${name} 必须是 ${minimum}-${maximum} 的整数`);
  }
}

export function encodeUint16BE(value: number): [number, number] {
  assertInteger(value, 0, 0xffff, "uint16");
  return [(value >>> 8) & 0xff, value & 0xff];
}

export function encodeInt16BE(value: number): [number, number] {
  assertInteger(value, -0x8000, 0x7fff, "int16");
  const encoded = value & 0xffff;
  return [(encoded >>> 8) & 0xff, encoded & 0xff];
}

export function decodeInt16BE(high: number, low: number): number {
  assertInteger(high, 0, 0xff, "high");
  assertInteger(low, 0, 0xff, "low");
  const encoded = (high << 8) | low;
  return encoded & 0x8000 ? encoded - 0x10000 : encoded;
}

export function bytesToHex(bytes: readonly number[]): string {
  return bytes.map((byte) => byte.toString(16).padStart(2, "0").toUpperCase()).join(" ");
}
